        // =========================================================
        // STUDENTS
        // =========================================================
        function renderStudents() {
            const q = (document.getElementById('student-search').value || '').toLowerCase();
            const st = (document.getElementById('filter-stage') || { value: '' }).value;
            const allowedStgs = IS_TEACHER_MODE ? getTeacherAllowedStages() : null;
            // الخريجون يظهرون فقط في صفحة الخريجين ولا يُعرضون ضمن قائمة الطلاب النشطين
            const isGradStatus = s => { const _s = String(s.status || ''); return _s.indexOf('خريج') !== -1 || _s.indexOf('متخرج') !== -1; };
            const list = _sortStudentsForPrint(DB.students.filter(s =>
                !isGradStatus(s) &&
                (!q || s.name.toLowerCase().includes(q)) &&
                (!st || s.stage === st) &&
                (!allowedStgs || allowedStgs.includes(s.stage))
            ), st || '', '1');
            // تحديث شارة عدد الطلاب
            const badge = document.getElementById('students-count-badge');
            if (badge) {
                const total = DB.students.filter(s => !isGradStatus(s) && (!st || s.stage === st) && (!allowedStgs || allowedStgs.includes(s.stage))).length;
                const repeaters = list.filter(s => (s.status || '').indexOf('راسب') !== -1).length; badge.textContent = (st ? `${list.length} طالب — ${st}` : list.length + ' طالب إجمالي') + (repeaters ? ` | 🔄 ${repeaters} معيد` : '');
                badge.style.display = list.length ? '' : 'none';
            }
            const tbody = document.getElementById('students-tbody'), empty = document.getElementById('students-empty');
            if (!list.length) { tbody.innerHTML = ''; empty.style.display = 'block'; return; } empty.style.display = 'none';
            tbody.innerHTML = list.map(s => {
                const age = s.dob ? calcAge(s.dob) : '-'; const dl = getDaysUntilBirthday(s.dob);
                let bb = '-'; if (dl !== null) { if (dl === 0) bb = `<span class="badge b-bday">🎂 اليوم!</span>`; else if (dl <= (DB.settings.bdayDays || 7)) bb = `<span class="badge b-bday">بعد ${dl} يوم</span>`; else bb = `<span style="font-size:11px;color:var(--muted)">${dl} يوم</span>`; }
                const nc = spGetNotesCount(s.id); return `<tr><td style="font-size:11px;font-weight:700;color:var(--navy);direction:ltr">${s.code || s.id}</td><td class="td-name"><div style="display:flex;align-items:center;gap:8px">${s.photo ? `<img src="${s.photo}" class="student-avatar">` : `<div class="student-avatar-placeholder">👤</div>`}<span style="cursor:pointer;text-decoration:underline dotted;text-underline-offset:3px" onclick="openSP('${s.id}')" title="عرض ملف الطالب">${s.name}</span>${(s.status || '').indexOf('راسب') !== -1 ? '<span style="background:linear-gradient(135deg,#fecaca,#fca5a5);color:#991b1b;border:1px solid #f87171;border-radius:10px;padding:1px 8px;font-size:10px;font-weight:900;margin-right:4px" title="طالب معيد — رسب العام الماضي">🔄 معيد</span>' : ''}${nc ? `<span style="background:#e8f4ff;color:#1e40af;border-radius:20px;padding:1px 7px;font-size:10px;font-weight:700;cursor:pointer" onclick="openSPNotes('${s.id}')" title="يوجد ${nc} ملاحظة">📝 ${nc}</span>` : ''}</div></td><td><span class="badge b-info">${s.stage}</span></td><td>${s.gender || '-'}${s.deacon ? ` <span style="font-size:10px;background:linear-gradient(135deg,#fdf3d8,#fde8a0);color:#7a4f00;border:1px solid #e8c04a;border-radius:10px;padding:1px 7px;font-weight:900">✝️ شماس</span>` : ''}</td><td style="direction:ltr;font-size:11px">${s.dob || '-'}</td><td>${age}</td><td>${bb}</td><td style="direction:ltr;font-size:12px">${s.phone || '-'}</td><td style="font-size:11px">${s.address || '-'}</td><td><span class="badge b-warn">${s.status || '-'}</span></td><td style="font-size:11px">${s.father || '-'}</td>
    <td style="white-space:nowrap">
      <button class="btn btn-outline btn-sm allow-ro" onclick="editStudent('${s.id}')">✏️</button>
      ${(s.phone || s.phone2) ? `<button class="btn btn-sm allow-ro" title="إرسال واتساب" onclick="quickWA('${s.id}')" style="background:linear-gradient(135deg,#075e54,#25d366);color:#fff;border:none">💬</button>` : ''}
      <button class="btn btn-danger btn-sm allow-ro" onclick="deleteStudent('${s.id}')">🗑️</button>
    </td></tr>`;
            }).join('');
        }
        function calcAge(dob) { try { const b = _parseDobLocal(dob); if (!b) return '-'; const n = new Date(); let a = n.getFullYear() - b.getFullYear(); if (n.getMonth() - b.getMonth() < 0 || (n.getMonth() - b.getMonth() === 0 && n.getDate() < b.getDate())) a--; return a >= 0 ? a + ' سنة' : '-'; } catch (e) { return '-'; } }
        function toggleDeaconField() {
            const g = document.getElementById('s-gender');
            const f = document.getElementById('deacon-field');
            if (f) f.style.display = g && g.value === 'ذكر' ? 'flex' : 'none';
        }
        function openAddStudentModal() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط — سجّل دخولك للتعديل'); return; }
            document.getElementById('modal-student-title').textContent = '➕ إضافة طالب جديد';
            ['s-name', 's-phone', 's-phone2', 's-address', 's-father'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
            ['s-dob', 's-paid'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
            const yr = document.getElementById('s-year'); if (yr) yr.value = DB.schoolYear;
            const gdr = document.getElementById('s-gender'); if (gdr) gdr.value = 'ذكر';
            const dc = document.getElementById('s-deacon'); if (dc) dc.checked = false;
            toggleDeaconField();
            const sts = document.getElementById('s-status'); if (sts) sts.value = 'جديد';
            // ذكاء: اختار المرحلة اللي المستخدم واقف عليها حالياً
            const currentStage = (document.getElementById('filter-stage') || {}).value || '';
            document.getElementById('s-stage').innerHTML = STAGES.map(s => `<option value="${s}"${s === currentStage ? ' selected' : ''}>${s}</option>`).join('');
            document.getElementById('save-student-btn').onclick = saveStudent;
            // إخفاء حقل الكود في وضع الإضافة (سيُولَّد تلقائياً عند الحفظ)
            const _codeWrap = document.getElementById('s-code-wrap');
            if (_codeWrap) _codeWrap.style.display = 'none';
            resetStudentPhotoUI('');
            openModal('modal-student');
        }
        function editStudent(id) {
            try {
                if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط — سجّل دخولك للتعديل'); return; }
                const s = DB.students.find(x => x.id == id); if (!s) { showToast('⚠️ لم يُعثر على الطالب'); return; }
                document.getElementById('modal-student-title').textContent = '✏️ تعديل بيانات الطالب';
                document.getElementById('s-name').value = s.name || ''; document.getElementById('s-phone').value = s.phone || ''; document.getElementById('s-phone2').value = s.phone2 || ''; document.getElementById('s-address').value = s.address || ''; document.getElementById('s-father').value = s.father || ''; document.getElementById('s-dob').value = s.dob || ''; document.getElementById('s-paid').value = s.paid || ''; document.getElementById('s-year').value = s.year || ''; document.getElementById('s-gender').value = s.gender || 'ذكر'; document.getElementById('s-status').value = s.status || 'جديد'; const _dc = document.getElementById('s-deacon'); if (_dc) _dc.checked = !!(s.deacon); toggleDeaconField();
                document.getElementById('s-stage').innerHTML = STAGES.map(st => `<option value="${st}"${st === s.stage ? ' selected' : ''}>${st}</option>`).join('');
                document.getElementById('save-student-btn').onclick = () => updateStudent(id);
                // ✅ إظهار كود الطالب عند التعديل
                const _codeWrap2 = document.getElementById('s-code-wrap');
                const _codeDisp = document.getElementById('s-code-display');
                if (_codeWrap2 && _codeDisp) {
                    if (s.code) {
                        _codeDisp.textContent = s.code;
                        _codeWrap2.style.display = '';
                    } else {
                        _codeDisp.textContent = '⚠️ لا يوجد كود — سيُولَّد عند الحفظ';
                        _codeWrap2.style.display = '';
                    }
                }
                resetStudentPhotoUI(s.photo || '');
                openModal('modal-student');
            } catch (err) {
                console.error('editStudent error:', err);
                showToast('⚠️ خطأ: ' + err.message);
            }
        }
        async function saveStudent() {
            if (!IS_EDIT_MODE) return;
            if (window._photoUploading) { showToast('⏳ انتظر اكتمال رفع الصورة...'); return; }
            { const _ph = document.getElementById('s-photo').value; if (_ph && _ph.startsWith('data:image')) { showToast('⚠️ لم يكتمل رفع الصورة على السحابة — أعد اختيارها'); return; } }
            const name = document.getElementById('s-name').value.trim(); if (!name) { showToast('⚠️ أدخل اسم الطالب'); return; }
            const stage = document.getElementById('s-stage').value;
            if (!stage) { showToast('⚠️ اختر المرحلة الدراسية'); return; }
            // منع تكرار الاسم في نفس المرحلة
            const isDuplicate = DB.students.some(s => s.name.trim() === name && s.stage === stage);
            if (isDuplicate) { showToast('⚠️ يوجد طالب بنفس الاسم في هذه المرحلة'); return; }
            const _enrollStage = stage; const _enrollYear = (document.getElementById('s-year').value || DB.schoolYear); const _newCode = generateStudentCode(_enrollStage, _enrollYear);
            // ✅ تحقق صارم: تأكد أن الكود فريد فعلاً (حماية إضافية)
            const _allCodes = new Set(DB.students.map(s => s.code).filter(Boolean));
            if (_allCodes.has(_newCode)) {
                // في حالة نادرة جداً: أعد التوليد
                let _retry = 0, _safeCode = _newCode;
                while (_allCodes.has(_safeCode) && _retry < 50) {
                    _retry++;
                    _safeCode = generateStudentCode(_enrollStage, _enrollYear);
                }
                if (_allCodes.has(_safeCode)) { showToast('❌ فشل توليد كود فريد — راجع العدادات'); return; }
            } DB.students.push({ id: 'S' + DB.nextId++, code: _newCode, enrollmentStage: _enrollStage, enrollmentYear: _enrollYear, name, stage, gender: document.getElementById('s-gender').value, deacon: document.getElementById('s-gender').value === 'ذكر' && document.getElementById('s-deacon').checked, dob: document.getElementById('s-dob').value, phone: document.getElementById('s-phone').value, phone2: document.getElementById('s-phone2').value, address: document.getElementById('s-address').value, father: document.getElementById('s-father').value, year: document.getElementById('s-year').value, status: document.getElementById('s-status').value, paid: document.getElementById('s-paid').value, photo: document.getElementById('s-photo').value });
            logTeacherActivity('طالب', `إضافة طالب جديد: ${name} — المرحلة: ${stage}`);
            await saveDB(); renderStudents(); closeModal('modal-student'); showToast('✅ تم إضافة الطالب');
        }
        async function updateStudent(id) {
            if (!IS_EDIT_MODE) return;
            if (window._photoUploading) { showToast('⏳ انتظر اكتمال رفع الصورة...'); return; }
            { const _ph = document.getElementById('s-photo').value; if (_ph && _ph.startsWith('data:image')) { showToast('⚠️ لم يكتمل رفع الصورة على السحابة — أعد اختيارها'); return; } }
            const s = DB.students.find(x => x.id == id); if (!s) return;
            const oldName = s.name;
            s.name = document.getElementById('s-name').value.trim(); s.stage = document.getElementById('s-stage').value; s.gender = document.getElementById('s-gender').value; s.deacon = s.gender === 'ذكر' && document.getElementById('s-deacon').checked; s.dob = document.getElementById('s-dob').value; s.phone = document.getElementById('s-phone').value; s.phone2 = document.getElementById('s-phone2').value; s.address = document.getElementById('s-address').value; s.father = document.getElementById('s-father').value; s.year = document.getElementById('s-year').value; s.status = document.getElementById('s-status').value; s.paid = document.getElementById('s-paid').value; s.photo = document.getElementById('s-photo').value;
            // ✅ توليد كود تلقائي إذا كان الطالب بدون كود (طلاب قدامى)
            if (!s.code) {
                const _eStage = s.enrollmentStage || s.stage;
                const _eYear = s.enrollmentYear || s.year || DB.schoolYear;
                s.code = generateStudentCode(_eStage, _eYear);
                if (!s.enrollmentStage) s.enrollmentStage = _eStage;
                if (!s.enrollmentYear) s.enrollmentYear = _eYear;
                showToast('🔑 تم توليد كود دائم للطالب: ' + s.code);
            }
            // ✅ التحقق من عدم تكرار الكود مع طالب آخر
            const _dupCode = DB.students.find(x => x.id !== id && x.code && x.code === s.code);
            if (_dupCode) {
                showToast('❌ كود مكرر مع الطالب: ' + _dupCode.name + ' — راجع البيانات');
                return;
            }
            logTeacherActivity('طالب', `تعديل بيانات طالب: ${s.name} — المرحلة: ${s.stage}`);
            await saveDB(); renderStudents(); closeModal('modal-student'); showToast('✅ تم التحديث');
        }
        function deleteStudent(id) {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            if (IS_TEACHER_MODE) { showToast('⚠️ غير مسموح — حذف الطلاب للأدمن فقط'); return; }
            const st = DB.students.find(s => s.id == id);
            const hasGrades = st && DB.grades && Object.keys(DB.grades).some(k => k.startsWith(st.id + '_'));
            const hasAbsence = st && DB.absence && Object.keys(DB.absence).some(k => k.startsWith(st.id + '_'));
            const warn = hasGrades || hasAbsence ? '\n⚠️ تحذير: هذا الطالب لديه درجات/غياب مسجلة — ستُحذف نهائياً!' : '';
            if (!confirm('حذف الطالب: ' + (st ? st.name : '') + '؟' + warn)) return;
            DB.students = DB.students.filter(s => s.id != id);
            // حذف درجات وغياب الطالب
            if (DB.grades) Object.keys(DB.grades).filter(k => k.startsWith(id + '_')).forEach(k => delete DB.grades[k]);
            if (DB.absence) Object.keys(DB.absence).filter(k => k.startsWith(id + '_')).forEach(k => delete DB.absence[k]);
            saveDB().then(() => showToast('🗑️ تم حذف الطالب وجميع بياناته')); renderStudents();
        }
        // حذف خريج نهائياً (من صفحة الخريجين) مع تحديث الإحصائيات
        function deleteGraduate(id) {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            if (IS_TEACHER_MODE) { showToast('⚠️ غير مسموح — حذف الطلاب للأدمن فقط'); return; }
            const st = DB.students.find(s => s.id == id); if (!st) return;
            const hasGrades = DB.grades && Object.keys(DB.grades).some(k => k.startsWith(st.id + '_'));
            const hasAbsence = DB.absence && Object.keys(DB.absence).some(k => k.startsWith(st.id + '_'));
            const warn = hasGrades || hasAbsence ? '\n⚠️ تحذير: هذا الخريج لديه درجات/غياب مسجلة — ستُحذف نهائياً!' : '';
            if (!confirm('🗑️ حذف الخريج نهائياً: ' + (st.name || '') + '؟' + warn)) return;
            DB.students = DB.students.filter(s => s.id != id);
            if (DB.grades) Object.keys(DB.grades).filter(k => k.startsWith(id + '_')).forEach(k => delete DB.grades[k]);
            if (DB.absence) Object.keys(DB.absence).filter(k => k.startsWith(id + '_')).forEach(k => delete DB.absence[k]);
            try { logTeacherActivity('خريج', `حذف خريج: ${st.name}`); } catch (e) {}
            saveDB().then(() => showToast('🗑️ تم حذف الخريج وجميع بياناته'));
            if (typeof initGraduatesPage === 'function') initGraduatesPage();
            if (typeof renderDashboard === 'function') renderDashboard();
        }
        function exportStudentsCSV() {
            try {
                if (!DB.students || !DB.students.length) { showToast('⚠️ لا توجد بيانات للتصدير'); return; }
                const rows = [['الكود', 'الاسم', 'المرحلة', 'النوع', 'تاريخ الميلاد', 'الموبايل', 'العنوان', 'أب الاعتراف', 'العام', 'الحالة']];
                DB.students.forEach(s => rows.push([s.code || s.id, s.name, s.stage, s.gender || '', s.dob || '', s.phone || '', s.address || '', s.father || '', s.year || '', s.status || '']));
                const csv = rows.map(r => r.map(c => '"' + String(c).replace(/"/g, '""') + '"').join(',')).join('\n');
                const filename = 'الطلاب.csv';
                const a = document.createElement('a'); a.href = 'data:text/csv;charset=utf-8,\uFEFF' + encodeURIComponent(csv); a.download = filename; a.click();
                showToast('✅ تم التصدير بنجاح — ' + filename);
            } catch (e) {
                console.error('[exportStudentsCSV]', e);
                showToast('❌ فشل التصدير: ' + (e?.message || e));
            }
        }

        // =========================================================
        // EXCEL IMPORT
