            const sas = document.getElementById('smart-ai-status'); if (sas) sas.style.display = 'none';
            const sss = document.getElementById('smart-sheet-selector'); if (sss) sss.style.display = 'none';
            _excelGradesData = null; _gradeImageB64 = null; _smartRawSheets = null; _pdfPages = [];
