        function onGradeImportStageChange() {
            const stage = (document.getElementById('grade-import-stage') || { value: '' }).value;
            const subjs = stage ? (DB.subjects[stage] || []) : [];
            const sel = document.getElementById('grade-import-subject');
            if (sel) { sel.innerHTML = '<option value="">كل المواد</option>' + subjs.map(s => `<option value="${s.name}">${s.name}</option>`).join(''); }
        }

        function switchGradeTab(tab) {
            ['excel', 'image', 'template', 'smart'].forEach(t => {
                const panel = document.getElementById('gi-panel-' + t);
                const btn = document.getElementById('gi-tab-' + t);
                if (panel) panel.style.display = t === tab ? 'block' : 'none';
                if (!btn) return;
                if (t === 'smart') {
                    btn.style.background = t === tab ? 'linear-gradient(135deg,#7c3aed,#9f67fa)' : 'var(--bg)';
                    btn.style.color = t === tab ? '#fff' : '#7c3aed';
                    return;
                }
                if (t === 'image') {
                    btn.style.background = t === tab ? 'linear-gradient(135deg,#15803d,#22a052)' : 'var(--bg)';
                    btn.style.color = t === tab ? '#fff' : '#15803d';
                    btn.style.cursor = 'pointer';
                    return;
                }
                btn.style.background = t === tab ? 'var(--navy)' : 'var(--bg)';
                btn.style.color = t === tab ? '#fff' : 'var(--navy)';
            });
            if (!['excel', 'smart', 'image'].includes(tab)) document.getElementById('excel-import-btn-grades').style.display = 'none';
            if (tab === 'image') { try { onAIProviderChange(); } catch (e) { } }
        }

        let _gradeImageB64 = null;
        let _smartRawSheets = null;
        let _pdfPages = []; // [{dataUrl, base64, mtype}]

        // =========================================================
        // SMART AI EXCEL IMPORT
        // =========================================================

        function handleSmartDrop(e) {
            e.preventDefault();
            document.getElementById('smart-drop-zone').style.background = '';
            const file = e.dataTransfer.files[0];
            if (!file) return;
            processSmartFile(file);
        }

        function handleSmartExcelFile(e) {
            const file = e.target.files[0]; if (!file) return;
            processSmartFile(file);
            e.target.value = '';
        }

        function processSmartFile(file) {
            const reader = new FileReader();
            reader.onload = ev => {
                try {
                    let sheets = {};
                    if (file.name.toLowerCase().endsWith('.csv')) {
                        // CSV = single sheet
                        const rows = ev.target.result.split('\n').filter(r => r.trim()).map(r => {
                            const res = []; let cur = '', inQ = false;
                            for (let i = 0; i < r.length; i++) { const c = r[i]; if (c === '"') { inQ = !inQ; } else if (c === ',' && !inQ) { res.push(cur.trim()); cur = ''; } else cur += c; }
                            res.push(cur.trim()); return res;
                        });
                        sheets['Sheet1'] = rows;
                    } else {
                        const wb = XLSX.read(new Uint8Array(ev.target.result), { type: 'array' });
                        wb.SheetNames.forEach(sn => {
                            const ws = wb.Sheets[sn];
                            sheets[sn] = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
                        });
                    }
                    _smartRawSheets = sheets;
                    const names = Object.keys(sheets);
                    if (names.length > 1) {
                        // Show sheet selector
                        const stage = (document.getElementById('grade-import-stage') || { value: '' }).value;
                        const sss = document.getElementById('smart-sheet-selector');
                        sss.style.display = 'block';
                        sss.innerHTML = `<div style="background:#f0f4ff;border:1px solid #c0d0ff;border-radius:10px;padding:10px 14px;font-size:12px;margin-bottom:8px">
          📋 الملف يحتوي على ${names.length} شيتات — اختر الشيت اللي فيه الدرجات أو اختر "كل الشيتات"
          <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:8px">
            <button class="btn btn-success btn-sm" onclick="runSmartAnalysis('__all__')">🤖 تحليل كل الشيتات</button>
            ${names.map(n => `<button class="btn btn-outline btn-sm" onclick="runSmartAnalysis('${n.replace(/'/g, "\\'")}')">📋 ${n}</button>`).join('')}
          </div>
        </div>`;
                    } else {
                        runSmartAnalysis(names[0]);
                    }
                } catch (ex) { showToast('⚠️ خطأ في قراءة الملف: ' + ex.message); }
            };
            if (file.name.toLowerCase().endsWith('.csv')) reader.readAsText(file, 'UTF-8');
            else reader.readAsArrayBuffer(file);
        }

        function runSmartAnalysis(sheetKey) {
            const stage = (document.getElementById('grade-import-stage') || { value: '' }).value;
            if (!stage) { showToast('⚠️ اختر المرحلة أولاً'); return; }
            if (!_smartRawSheets) { showToast('⚠️ ارفع ملف Excel أولاً'); return; }
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            const subjs = DB.subjects[stage] || [];
            if (!students.length) { showToast('⚠️ لا يوجد طلاب في هذه المرحلة'); return; }

            const statusEl = document.getElementById('smart-ai-status');
            const resultEl = document.getElementById('smart-ai-result');
            statusEl.style.display = 'block';
            document.getElementById('smart-ai-status-text').textContent = '🔍 جاري تحليل الشيت ومطابقة الأسماء...';
            resultEl.innerHTML = '';
            document.getElementById('excel-import-btn-grades').style.display = 'none';

            // Pick sheets
            let sheetsToUse = {};
            if (sheetKey === '__all__') sheetsToUse = _smartRawSheets;
            else sheetsToUse[sheetKey] = _smartRawSheets[sheetKey];

            // ── Normalize Arabic text for matching ──
            function normAr(s) {
                return String(s || '').trim()
                    .replace(/[أإآا]/g, 'ا').replace(/[ىي]/g, 'ي').replace(/ة/g, 'ه')
                    .replace(/\s+/g, ' ').toLowerCase();
            }

            // ── Fuzzy student match ──
            const studentsNorm = students.map(s => ({ s, norm: normAr(s.name), words: normAr(s.name).split(' ') }));
            function matchStudent(raw) {
                const rn = normAr(raw);
                if (!rn) return null;
                // Exact
                let m = studentsNorm.find(x => x.norm === rn); if (m) return m.s;
                // Contains full
                m = studentsNorm.find(x => x.norm.includes(rn) || rn.includes(x.norm)); if (m) return m.s;
                // First 2 words match
                const rw = rn.split(' ');
                m = studentsNorm.find(x => {
                    const overlap = rw.filter(w => w.length > 1 && x.words.includes(w)).length;
                    return overlap >= Math.min(2, rw.length, x.words.length);
                });
                return m ? m.s : null;
            }

            // ── Fuzzy subject match ──
            const subjsNorm = subjs.map(s => ({ s, norm: normAr(s.name) }));
            function matchSubj(raw) {
                const rn = normAr(raw.replace(/\s*[\(\[]\d+[\)\]]/g, '').replace(/\s*(من|\/)\s*\d+/g, ''));
                if (!rn) return null;
                let m = subjsNorm.find(x => x.norm === rn); if (m) return m.s;
                m = subjsNorm.find(x => x.norm.includes(rn) || rn.includes(x.norm)); if (m) return m.s;
                // Word overlap
                const rw = rn.split(' ').filter(w => w.length > 1);
                m = subjsNorm.find(x => rw.some(w => x.norm.includes(w)));
                return m ? m.s : null;
            }

            // field keywords
            const FIELD_KW = { behavior: ['سلوك', 'درجة سلوك'], oral: ['شفوي', 'شفهي', 'فم'], attendance: ['حضور', 'مداومة'], written: ['تحريري', 'كتابي', 'امتحان'] };
            function detectField(h) {
                for (const [f, kws] of Object.entries(FIELD_KW)) { if (kws.some(k => normAr(h).includes(normAr(k)))) return f; }
                return null;
            }

            // ── Process all sheets ──
            const allRows = {}; // student.id → {student_name, grades:{subjName:{b,o,a,w}}}
            let totalMatched = 0, totalUnmatched = 0;
            const unmatchedNames = [];

            Object.entries(sheetsToUse).forEach(([, rows]) => {
                if (!rows || rows.length < 2) return;
                const headers = (rows[0] || []).map(h => String(h || '').trim());
                const nameCol = headers.findIndex(h => normAr(h).includes('اسم') || normAr(h).includes('name')) || 0;

                // Detect column map
                // Format A: الاسم | المادة | سلوك | شفوي | حضور | تحريري
                const subjCol = headers.findIndex(h => normAr(h).includes('ماد') || normAr(h).includes('subject'));
                const bCol = headers.findIndex(h => detectField(h) === 'behavior' && !h.includes(' - '));
                const oCol = headers.findIndex(h => detectField(h) === 'oral' && !h.includes(' - '));
                const aCol = headers.findIndex(h => detectField(h) === 'attendance' && !h.includes(' - '));
                const wCol = headers.findIndex(h => detectField(h) === 'written' && !h.includes(' - '));

                if (subjCol !== -1 && (bCol !== -1 || oCol !== -1 || wCol !== -1)) {
                    // Format A: one row per student-subject
                    rows.slice(1).forEach(row => {
                        const nm = String(row[nameCol >= 0 ? nameCol : 0] || '').trim();
                        const sb = String(row[subjCol] || '').trim();
                        if (!nm) return;
                        const st = matchStudent(nm);
                        if (!st) { if (nm && !unmatchedNames.includes(nm)) unmatchedNames.push(nm); totalUnmatched++; return; }
                        const matchedSubj = matchSubj(sb);
                        if (!matchedSubj) return;
                        if (!allRows[st.id]) allRows[st.id] = { student_name: st.name, grades: {} };
                        if (!allRows[st.id].grades[matchedSubj.name]) allRows[st.id].grades[matchedSubj.name] = { behavior: 0, oral: 0, attendance: 0, written: 0 };
                        const g = allRows[st.id].grades[matchedSubj.name];
                        if (bCol !== -1 && String(row[bCol] || '').trim()) g.behavior = parseFloat(row[bCol]) || 0;
                        if (oCol !== -1 && String(row[oCol] || '').trim()) g.oral = parseFloat(row[oCol]) || 0;
                        if (aCol !== -1 && String(row[aCol] || '').trim()) g.attendance = parseFloat(row[aCol]) || 0;
                        if (wCol !== -1 && String(row[wCol] || '').trim()) g.written = parseFloat(row[wCol]) || 0;
                        totalMatched++;
                    });
                } else {
                    // Format B/C: wide format — each column = subject or subject-field
                    const colMap = [];
                    headers.forEach((h, i) => {
                        if (i === (nameCol >= 0 ? nameCol : 0)) return;
                        if (!String(h || '').trim()) return;
                        // "SubjName - field (max)"
                        const dashM = h.match(/^(.+?)\s*-\s*(سلوك|شفوي|حضور|تحريري)/);
                        if (dashM) {
                            const sn = dashM[1].trim().replace(/\s*\(\d+\)/, '');
                            const ms = matchSubj(sn);
                            const ft = { 'سلوك': 'behavior', 'شفوي': 'oral', 'شفهي': 'oral', 'حضور': 'attendance', 'تحريري': 'written' }[dashM[2]] || 'oral';
                            if (ms) colMap.push({ i, subj: ms.name, field: ft });
                            return;
                        }
                        // Detect field first
                        const fieldGuess = detectField(h);
                        if (fieldGuess) {
                            // Standalone field col — try to match to last seen subject header
                            const prevSubjEntry = [...colMap].reverse().find(c => c.subj);
                            if (prevSubjEntry) colMap.push({ i, subj: prevSubjEntry.subj, field: fieldGuess });
                            return;
                        }
                        // Pure subject column
                        const ms = matchSubj(h);
                        if (ms) colMap.push({ i, subj: ms.name, field: 'oral' });
                    });

                    rows.slice(1).forEach(row => {
                        const nm = String(row[nameCol >= 0 ? nameCol : 0] || '').trim(); if (!nm) return;
                        const st = matchStudent(nm);
                        if (!st) { if (!unmatchedNames.includes(nm)) unmatchedNames.push(nm); totalUnmatched++; return; }
                        if (!allRows[st.id]) allRows[st.id] = { student_name: st.name, grades: {} };
                        colMap.forEach(({ i, subj, field }) => {
                            const val = String(row[i] || '').trim();
                            if (!val) return;
                            const num = parseFloat(val);
                            if (isNaN(num)) return;
                            if (!allRows[st.id].grades[subj]) allRows[st.id].grades[subj] = { behavior: 0, oral: 0, attendance: 0, written: 0 };
                            allRows[st.id].grades[subj][field] = num;
                        });
                        totalMatched++;
                    });
                }
            });

            statusEl.style.display = 'none';
            const finalRows = Object.values(allRows);
            const notes = totalUnmatched > 0 ? `⚠️ ${totalUnmatched} صف لم يُطابق: ${unmatchedNames.slice(0, 3).join('، ')}${unmatchedNames.length > 3 ? '...' : ''}` :
                `✅ تم مطابقة ${finalRows.length} طالب بنجاح`;
            _excelGradesData = { fromImage: true, rows: finalRows };
            renderSmartGradesPreview({ rows: finalRows, notes }, stage);
        }

        function renderSmartGradesPreview(parsed, stage) {
            const resultEl = document.getElementById('smart-ai-result');
            const rows = parsed.rows || [];
            const notes = parsed.notes || '';
            if (!rows.length) {
                resultEl.innerHTML = `<div style="background:#fff3cd;border:1px solid #ffc107;border-radius:10px;padding:12px;color:#856404;font-size:12px">
      ⚠️ لم يتم العثور على درجات قابلة للمطابقة — تأكد من اختيار المرحلة الصحيحة<br>
      ${notes ? `<small>${notes}</small>` : ''}
    </div>`;
                return;
            }
            const allSubjs = new Set();
            rows.forEach(r => Object.keys(r.grades || {}).forEach(s => allSubjs.add(s)));
            const subjArr = [...allSubjs].slice(0, 8);
            let html = `
  <div style="background:linear-gradient(135deg,#f0fff4,#e8ffe8);border:1px solid #b8e6cc;border-radius:10px;padding:10px 14px;font-size:12px;font-weight:700;color:#1a5c2a;margin-bottom:10px">
    <div>تم مطابقة <b>${rows.length} طالب</b> — راجع المعاينة وأكد الاستيراد</div>
    ${notes ? `<div style="font-size:11px;color:var(--muted);margin-top:3px;font-weight:400">${notes}</div>` : ''}
  </div>
  <div class="tw"><table>
    <thead><tr>
      <th style="text-align:right">الاسم</th>
      ${subjArr.map(s => `<th>${s}</th>`).join('')}
      ${allSubjs.size > 8 ? `<th>+${allSubjs.size - 8}</th>` : ''}
    </tr></thead><tbody>`;
            rows.slice(0, 12).forEach(r => {
                html += `<tr><td style="text-align:right;font-weight:700;font-size:12px">${r.student_name}</td>`;
                subjArr.forEach(s => {
                    const g = r.grades[s] || {};
                    const t = (+g.behavior || 0) + (+g.oral || 0) + (+g.attendance || 0) + (+g.written || 0);
                    html += t > 0 ? `<td><span style="color:var(--green);font-weight:700">${t}</span></td>` : `<td style="color:#ddd">—</td>`;
                });
                if (allSubjs.size > 8) html += `<td style="color:var(--muted);font-size:10px">...</td>`;
                html += `</tr>`;
            });
            if (rows.length > 12) html += `<tr><td colspan="${subjArr.length + 2}" style="text-align:center;color:var(--muted);font-size:11px;padding:8px">... و ${rows.length - 12} طالب آخر</td></tr>`;
            html += `</tbody></table></div>`;
            resultEl.innerHTML = html;
            document.getElementById('excel-import-btn-grades').style.display = 'flex';
        }

        function handleGradeImageFile(e) {
            const file = e.target.files[0]; if (!file) return;
            const reader = new FileReader();
            reader.onload = ev => {
                _gradeImageB64 = ev.target.result.split(',')[1];
                const mtype = file.type || 'image/jpeg';
                document.getElementById('grade-image-preview').innerHTML = `<img src="${ev.target.result}" style="max-width:100%;border-radius:10px;border:2px solid var(--border);max-height:280px;object-fit:contain">`;
                document.getElementById('excel-import-btn-grades').style.display = 'none';
                // Auto-analyze
                analyzeGradeImage(mtype);
            };
            reader.readAsDataURL(file);
            e.target.value = '';
        }

        async function analyzeGradeImage(mtype) {
            const stage = (document.getElementById('grade-import-stage') || { value: '' }).value;
            const students = DB.students.filter(s => s.stage === stage).map(s => s.name);
            const subjs = (DB.subjects[stage] || []).map(s => s.name);
            const statusEl = document.getElementById('grade-ai-status');
            const resultEl = document.getElementById('grade-ai-result');
            statusEl.style.display = 'block';
            resultEl.innerHTML = '';

            const prompt = `أنت مساعد لاستخراج درجات من كشف مدرسي.
المطلوب: اقرأ الصورة واستخرج درجات كل طالب لكل مادة.

أسماء الطلاب المتوقعة: ${students.slice(0, 40).join(' | ')}
المواد المتوقعة: ${subjs.join(' | ')}

أعد JSON فقط بهذا الشكل بدون أي نص آخر:
{
  "rows": [
    {"name": "اسم الطالب", "grades": {"اسم المادة": {"behavior":0,"oral":0,"attendance":0,"written":0}, ...}},
    ...
  ]
}
إذا وجدت درجة إجمالية فقط بدون تفصيل ضعها في "oral".
إذا لم تجد درجة اترك الحقل 0.`;

            try {
                const resp = await fetch('https://api.anthropic.com/v1/messages', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        model: 'claude-sonnet-4-20250514',
                        max_tokens: 4000,
                        messages: [{
                            role: 'user', content: [
                                { type: 'image', source: { type: 'base64', media_type: mtype, data: _gradeImageB64 } },
                                { type: 'text', text: prompt }
                            ]
                        }]
                    })
                });
                const data = await resp.json();
                const text = (data.content || []).map(c => c.text || '').join('');
                const clean = text.replace(/```json|```/g, '').trim();
                const parsed = JSON.parse(clean);
                statusEl.style.display = 'none';
                _excelGradesData = { fromImage: true, rows: parsed.rows };
                renderAIGradesPreview(parsed.rows, stage);
            } catch (err) {
                statusEl.style.display = 'none';
                resultEl.innerHTML = `<div style="background:#fee;border:1px solid #fcc;border-radius:10px;padding:12px;color:#c00;font-size:12px">❌ فشل في التحليل — تأكد من وضوح الصورة<br><small>${err.message}</small></div>`;
            }
        }

        // ═══════════════════════════════════════════════════════════════
        //  استخراج الدرجات من صور كشوف OCR بالذكاء الاصطناعي (Gemini / Claude)
        // ═══════════════════════════════════════════════════════════════
        function _getAIProvider() { return (document.getElementById('ai-provider') || { value: 'gemini' }).value; }
        function _getAIKey() {
            const inp = document.getElementById('ai-api-key');
            if (inp && inp.value.trim()) return inp.value.trim();
            return localStorage.getItem('bsh_ai_' + _getAIProvider() + '_key') || '';
        }
        function saveAIKey() {
            const inp = document.getElementById('ai-api-key');
            const k = (inp && inp.value.trim()) || '';
            if (!k) { showToast('⚠️ أدخل المفتاح أولاً'); return; }
            localStorage.setItem('bsh_ai_' + _getAIProvider() + '_key', k);
            showToast('✅ تم حفظ المفتاح على جهازك');
        }
        function onAIProviderChange() {
            const p = _getAIProvider();
            const inp = document.getElementById('ai-api-key');
            if (inp) inp.value = localStorage.getItem('bsh_ai_' + p + '_key') || '';
            const hint = document.getElementById('ai-key-hint');
            if (hint) hint.innerHTML = p === 'gemini'
                ? '🔑 احصل على مفتاح <b>مجاني</b> من <a href="https://aistudio.google.com/apikey" target="_blank" rel="noopener" style="color:#15803d;font-weight:700">Google AI Studio</a> — يُحفظ على جهازك فقط ولا يُرسَل لأي جهة أخرى.'
                : '🔑 احصل على مفتاح من <a href="https://console.anthropic.com/settings/keys" target="_blank" rel="noopener" style="color:#15803d;font-weight:700">Anthropic Console</a> — يُحفظ على جهازك فقط.';
        }

        function _compressGradeImage(file) {
            return new Promise((resolve, reject) => {
                const MAX_DIM = 1600; // أقصى عرض أو ارتفاع
                const QUALITY = 0.82; // جودة JPEG
                const reader = new FileReader();
                reader.onerror = reject;
                reader.onload = ev => {
                    const img = new Image();
                    img.onerror = () => {
                        // إذا فشل التحميل كصورة، أرسلها كما هي
                        resolve({ b64: ev.target.result.split(',')[1], mtype: file.type || 'image/jpeg', dataUrl: ev.target.result });
                    };
                    img.onload = () => {
                        let w = img.naturalWidth, h = img.naturalHeight;
                        // تصغير فقط إذا كانت أكبر من الحد
                        if (w > MAX_DIM || h > MAX_DIM) {
                            const ratio = Math.min(MAX_DIM / w, MAX_DIM / h);
                            w = Math.round(w * ratio);
                            h = Math.round(h * ratio);
                        }
                        const canvas = document.createElement('canvas');
                        canvas.width = w;
                        canvas.height = h;
                        const ctx = canvas.getContext('2d');
                        ctx.drawImage(img, 0, 0, w, h);
                        const dataUrl = canvas.toDataURL('image/jpeg', QUALITY);
                        const b64 = dataUrl.split(',')[1];
                        // تحرير الذاكرة
                        canvas.width = 0; canvas.height = 0;
                        resolve({ b64, mtype: 'image/jpeg', dataUrl });
                    };
                    img.src = ev.target.result;
                };
                reader.readAsDataURL(file);
            });
        }

        async function handleGradeImageFiles(e) {
            const files = Array.from(e.target.files || []);
            if (!files.length) return;
            window._gradeImagesB64 = window._gradeImagesB64 || [];
            showToast('⏳ جاري ضغط ' + files.length + ' صورة...');
            let done = 0;
            for (const file of files) {
                try {
                    const compressed = await _compressGradeImage(file);
                    window._gradeImagesB64.push(compressed);
                    done++;
                } catch (err) {
                    console.warn('فشل ضغط صورة:', err);
                    // fallback: أرسلها بدون ضغط
                    const raw = await new Promise(r => { const rd = new FileReader(); rd.onload = ev => r(ev.target.result); rd.readAsDataURL(file); });
                    window._gradeImagesB64.push({ b64: raw.split(',')[1], mtype: file.type || 'image/jpeg', dataUrl: raw });
                    done++;
                }
            }
            showToast('✅ تم ضغط ' + done + ' صورة بنجاح');
            _renderGradeThumbs();
            e.target.value = '';
        }
        function _renderGradeThumbs() {
            const el = document.getElementById('grade-image-preview');
            const imgs = window._gradeImagesB64 || [];
            el.innerHTML = imgs.map((im, i) => `<div style="position:relative"><img src="${im.dataUrl}" style="width:90px;height:90px;object-fit:cover;border-radius:8px;border:2px solid var(--border)"><button onclick="_removeGradeImg(${i})" title="حذف" style="position:absolute;top:-6px;left:-6px;background:#c0392b;color:#fff;border:none;border-radius:50%;width:22px;height:22px;cursor:pointer;font-weight:900;line-height:1">×</button><div style="position:absolute;bottom:2px;right:4px;background:rgba(0,0,0,.6);color:#fff;font-size:10px;border-radius:4px;padding:0 5px">${i + 1}</div></div>`).join('');
            const ab = document.getElementById('grade-ai-analyze-btn');
            if (ab) ab.style.display = imgs.length ? 'inline-flex' : 'none';
            const ib = document.getElementById('excel-import-btn-grades');
            if (ib) ib.style.display = 'none';
        }
        function _removeGradeImg(i) { (window._gradeImagesB64 || []).splice(i, 1); _renderGradeThumbs(); document.getElementById('grade-ai-result').innerHTML = ''; }

        async function _callGeminiVision(key, prompt, images) {
            const model = 'gemini-2.5-flash';
            const parts = [{ text: prompt }];
            images.forEach(im => parts.push({ inline_data: { mime_type: im.mtype || 'image/jpeg', data: im.b64 } }));
            const resp = await fetch('https://generativelanguage.googleapis.com/v1beta/models/' + model + ':generateContent?key=' + encodeURIComponent(key), {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ contents: [{ parts }], generationConfig: { temperature: 0, response_mime_type: 'application/json' } })
            });
            const data = await resp.json();
            if (data.error) throw new Error(data.error.message || 'Gemini API error');
            const cand = (data.candidates || [])[0] || {};
            return (((cand.content || {}).parts) || []).map(p => p.text || '').join('');
        }
        async function _callClaudeVision(key, prompt, images) {
            const content = images.map(im => ({ type: 'image', source: { type: 'base64', media_type: im.mtype || 'image/jpeg', data: im.b64 } }));
            content.push({ type: 'text', text: prompt });
            const resp = await fetch('https://api.anthropic.com/v1/messages', {
                method: 'POST',
                headers: { 'content-type': 'application/json', 'x-api-key': key, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true' },
                body: JSON.stringify({ model: 'claude-3-5-sonnet-20241022', max_tokens: 4000, messages: [{ role: 'user', content }] })
            });
            const data = await resp.json();
            if (data.error) throw new Error(data.error.message || 'Claude API error');
            return (data.content || []).map(c => c.text || '').join('');
        }

        async function analyzeGradeImagesAI() {
            const imgs = window._gradeImagesB64 || [];
            if (!imgs.length) { showToast('⚠️ ارفع صورة واحدة على الأقل'); return; }
            const provider = _getAIProvider();
            const key = _getAIKey();
            if (!key) { showToast('⚠️ أدخل مفتاح الـ API أولاً واحفظه'); return; }
            const stage = (document.getElementById('grade-import-stage') || { value: '' }).value;
            if (!stage) { showToast('⚠️ اختر المرحلة أولاً'); return; }
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s)).map(s => s.name);
            const subjList = (DB.subjects[stage] || []);
            if (!subjList.length) { showToast('⚠️ لا توجد مواد لهذه المرحلة'); return; }
            const subjInfo = subjList.map(s => {
                const p = [];
                if (s.behavior > 0) p.push('سلوك(/' + s.behavior + ')');
                if (s.oral > 0) p.push('شفوي(/' + s.oral + ')');
                if (s.attendance > 0) p.push('حضور(/' + s.attendance + ')');
                if (s.written > 0) p.push('تحريري(/' + s.written + ')');
                return '• ' + s.name + ': ' + p.join('، ');
            }).join('\n');
            const prompt = `أنت مساعد دقيق لاستخراج الدرجات من كشوف رصد مدرسية مصوّرة (نظام OCR).
في كل ورقة: أسماء الطلاب مطبوعة بوضوح في عمود "اسم الطالب"، وعناوين المواد والحقول مطبوعة، أمّا الدرجات فمكتوبة بخط اليد داخل مربعات أرقام منفصلة (كل خانة بها رقم واحد). الرقم الرمادي الباهت (0) هو دليل فقط ويعني "فارغ" إن لم يُكتب فوقه رقم بخط اليد.

المواد وحقولها لهذه المرحلة (مع الحد الأقصى لكل حقل):
${subjInfo}

أسماء الطلاب المتوقعة (طابِق الأسماء المطبوعة معها حرفيًا قدر الإمكان):
${students.join(' | ')}

اقرأ كل الصور المرفقة (قد تكون عدة صفحات لنفس الكشف) واستخرج درجة كل طالب لكل مادة.
أعِد JSON فقط بدون أي نص آخر بهذا الشكل بالضبط:
{"rows":[{"name":"اسم الطالب كما هو مطبوع","grades":{"اسم المادة":{"behavior":0,"oral":0,"attendance":0,"written":0}}}]}

قواعد مهمة:
- استخدم المفاتيح الإنجليزية: behavior=سلوك، oral=شفوي، attendance=حضور، written=تحريري.
- ضع 0 لأي حقل غير موجود في المادة أو فارغ (لم يُكتب فوقه رقم).
- لا تتجاوز الحد الأقصى المذكور لكل حقل.
- لا تخترع طلابًا غير موجودين، وأدرج كل الطلاب الظاهرين في الصور.`;
            const statusEl = document.getElementById('grade-ai-status');
            const resultEl = document.getElementById('grade-ai-result');
            statusEl.style.display = 'block'; resultEl.innerHTML = '';
            try {
                const text = provider === 'claude' ? await _callClaudeVision(key, prompt, imgs) : await _callGeminiVision(key, prompt, imgs);
                const clean = String(text || '').replace(/```json|```/g, '').trim();
                const parsed = JSON.parse(clean);
                statusEl.style.display = 'none';
                if (!parsed.rows || !parsed.rows.length) { resultEl.innerHTML = '<div style="color:var(--muted);font-size:13px;padding:12px">لم يتم العثور على درجات — تأكد من وضوح الصور</div>'; return; }
                _excelGradesData = { fromImage: true, rows: parsed.rows };
                renderAIGradesPreview(parsed.rows, stage);
            } catch (err) {
                statusEl.style.display = 'none';
                resultEl.innerHTML = '<div style="background:#fee;border:1px solid #fcc;border-radius:10px;padding:12px;color:#c00;font-size:12px">❌ فشل التحليل — ' + (err.message || err) + '<br><small>تأكد من صحة المفتاح، ووضوح الصور، والاتصال بالإنترنت.</small></div>';
            }
        }

        function renderAIGradesPreview(rows, stage) {
            const resultEl = document.getElementById('grade-ai-result');
            if (!rows || !rows.length) { resultEl.innerHTML = '<div style="color:var(--muted);font-size:13px;padding:12px">لم يتم العثور على درجات في الصورة</div>'; return; }
            const subjs = Object.keys(rows[0].grades || {});
            let html = `<div style="background:#f0fff4;border:1px solid #b8e6cc;border-radius:10px;padding:10px 14px;font-size:12px;font-weight:700;color:#1a5c2a;margin-bottom:8px">✅ تم استخراج ${rows.length} طالب — راجع البيانات ثم اضغط استيراد</div>`;
            html += `<div class="tw"><table><thead><tr><th style="text-align:right">الاسم</th>${subjs.map(s => `<th>${s}</th>`).join('')}</tr></thead><tbody>`;
            rows.slice(0, 8).forEach(r => {
                html += `<tr><td style="text-align:right;font-weight:700;font-size:12px">${r.name}</td>`;
                subjs.forEach(s => { const g = r.grades[s] || {}; const tot = (g.behavior || 0) + (g.oral || 0) + (g.attendance || 0) + (g.written || 0); html += `<td style="font-size:11px">${tot}</td>`; });
                html += `</tr>`;
            });
            if (rows.length > 8) html += `<tr><td colspan="${subjs.length + 1}" style="text-align:center;color:var(--muted);font-size:11px">... و ${rows.length - 8} طالب آخر</td></tr>`;
            html += `</tbody></table></div>`;
            resultEl.innerHTML = html;
            document.getElementById('excel-import-btn-grades').style.display = 'flex';
        }

        function handleGradesExcelFile(e) {
            const file = e.target.files[0]; if (!file) return;
            if (typeof XLSX === 'undefined') { showToast('⚠️ جاري تحميل مكتبة Excel، حاول تاني بعد ثانية'); e.target.value = ''; return; }
            const reader = new FileReader();
            reader.onload = ev => {
                try {
                    let data;
                    if (file.name.toLowerCase().endsWith('.csv')) {
                        data = ev.target.result.split('\n').filter(r => r.trim()).map(r => { const res = []; let cur = '', inQ = false; for (let i = 0; i < r.length; i++) { const c = r[i]; if (c === '"') { inQ = !inQ; } else if (c === ',' && !inQ) { res.push(cur.trim()); cur = ''; } else cur += c; } res.push(cur.trim()); return res; });
                    } else {
                        const wb = XLSX.read(new Uint8Array(ev.target.result), { type: 'array' });
                        // Try to find the best sheet — prefer one matching stage name
                        const stage = (document.getElementById('grade-import-stage') || { value: '' }).value;
                        let sheetName = wb.SheetNames[0];
                        if (stage) { const match = wb.SheetNames.find(n => n.includes(stage) || stage.includes(n)); if (match) sheetName = match; }
                        const ws = wb.Sheets[sheetName];
                        data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' });
                    }
                    _excelGradesData = { fromImage: false, raw: data };
                    previewExcelData(data, 'excel-preview-grades', 'excel-import-btn-grades');
                } catch (ex) { showToast('⚠️ خطأ في قراءة الملف: ' + ex.message); }
            };
            if (file.name.toLowerCase().endsWith('.csv')) reader.readAsText(file, 'UTF-8'); else reader.readAsArrayBuffer(file);
            e.target.value = '';
        }

        function downloadGradesTemplate() {
            try {
                const stage = (document.getElementById('grade-import-stage') || { value: '' }).value;
                if (!stage) { showToast('⚠️ اختر المرحلة أولاً'); return; }
                const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
                const subjs = DB.subjects[stage] || [];
                if (!students.length) { showToast('⚠️ لا يوجد طلاب في هذه المرحلة'); return; }
                if (!subjs.length) { showToast('⚠️ لا توجد مواد لهذه المرحلة'); return; }
                // Build header row
                const headers = ['الاسم'];
                subjs.forEach(s => {
                    if (s.behavior > 0) headers.push(s.name + ' - سلوك (' + s.behavior + ')');
                    if (s.oral > 0) headers.push(s.name + ' - شفوي (' + s.oral + ')');
                    if (s.attendance > 0) headers.push(s.name + ' - حضور (' + s.attendance + ')');
                    if (s.written > 0) headers.push(s.name + ' - تحريري (' + s.written + ')');
                });
                const rows = [headers];
                students.forEach(st => rows.push([st.name, ...headers.slice(1).map(() => '')]));
                const wb = XLSX.utils.book_new();
                const ws = XLSX.utils.aoa_to_sheet(rows);
                ws['!cols'] = [{ wch: 28 }, ...headers.slice(1).map(() => ({ wch: 16 }))];
                XLSX.utils.book_append_sheet(wb, ws, stage.slice(0, 31));
                const filename = 'رصد_درجات_' + stage + '_' + DB.schoolYear.replace(/\//g, '-') + '.xlsx';
                XLSX.writeFile(wb, filename);
                showToast('✅ تم التصدير بنجاح — ' + filename);
            } catch (e) {
                console.error('[downloadGradesTemplate]', e);
                showToast('❌ فشل التصدير: ' + (e?.message || e));
            }
        }
        function handleExcelFile(e, type) {
            const file = e.target.files[0]; if (!file) return;
            if (typeof XLSX === 'undefined') { showToast('⚠️ جاري تحميل مكتبة Excel، حاول تاني بعد ثانية'); e.target.value = ''; return; }
            const reader = new FileReader();
            reader.onload = ev => {
                try {
                    let data;
                    if (file.name.toLowerCase().endsWith('.csv')) { data = ev.target.result.split('\n').filter(r => r.trim()).map(r => { const res = []; let cur = '', inQ = false; for (let i = 0; i < r.length; i++) { const c = r[i]; if (c === '"') { inQ = !inQ; } else if (c === ',' && !inQ) { res.push(cur.trim()); cur = ''; } else cur += c; } res.push(cur.trim()); return res; }); }
                    else { const wb = XLSX.read(new Uint8Array(ev.target.result), { type: 'array' }); const ws = wb.Sheets[wb.SheetNames[0]]; data = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' }); }
                    if (type === 'students') { _excelStudentsData = data; previewExcelData(data, 'excel-preview-students', 'excel-import-btn-students'); }
                    else { _excelGradesData = data; previewExcelData(data, 'excel-preview-grades', 'excel-import-btn-grades'); }
                } catch (ex) { showToast('⚠️ خطأ في قراءة الملف: ' + ex.message); }
            };
            if (file.name.toLowerCase().endsWith('.csv')) reader.readAsText(file, 'UTF-8'); else reader.readAsArrayBuffer(file);
            e.target.value = '';
        }
        function previewExcelData(data, pid, bid) {
            if (!data || data.length < 2) { showToast('⚠️ الملف فارغ'); return; }
            const h = data[0], rows = data.slice(1, 5);
            document.getElementById(pid).innerHTML = `<div class="import-preview"><div style="padding:8px 12px;background:var(--bg);font-size:12px;font-weight:700;color:var(--muted)">معاينة (${data.length - 1} صف):</div><div class="tw"><table><thead><tr>${h.map(x => `<th>${x || ''}</th>`).join('')}</tr></thead><tbody>${rows.map(r => `<tr>${r.map(c => `<td style="font-size:11px">${c || ''}</td>`).join('')}</tr>`).join('')}</tbody></table></div></div>`;
            document.getElementById(bid).style.display = 'flex';
        }
        function confirmExcelImportStudents(forceOverwrite) {
            // ── Guard: ensure DB is valid ────────────────────────────────────────────
            if (!DB) { showToast('❌ البيانات غير محملة بعد — أعد تحميل الصفحة'); return; }
            if (!DB.students) DB.students = [];
            if (!DB.nextId) DB.nextId = 1;
            if (!DB.schoolYear) DB.schoolYear = '2024/2025';
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط — سجّل دخولك للتعديل'); return; }
            if (!_excelStudentsData) { showToast('⚠️ ارفع ملف Excel أولاً'); return; }
            const data = _excelStudentsData;
            if (!data || data.length < 2) { showToast('⚠️ الملف فارغ'); return; }

            try {
                // ── Normalize Arabic ──────────────────────────────────────────────────────
                function normAr(s) {
                    return String(s || '').trim()
                        .replace(/[ًٌٍَُِّْ]/g, '')
                        .replace(/[أإآٱ]/g, 'ا')
                        .replace(/[ىئ]/g, 'ي')
                        .replace(/ة/g, 'ه')
                        .replace(/\s+/g, ' ');
                }

                // ── Column detection ──────────────────────────────────────────────────────
                const rawHeaders = data[0];
                const headers = rawHeaders.map(h => normAr(String(h || '')));
                function findCol(...keywords) {
                    for (let i = 0; i < headers.length; i++) {
                        const h = headers[i];
                        if (!h) continue; // skip empty headers
                        if (keywords.some(k => { const nk = normAr(k); return nk && h.includes(nk); })) return i;
                    }
                    return -1;
                }
                const cName = findCol('اسم الطالب', 'اسم الطالب رباعي', 'اسم', 'name');
                const cStage = findCol('المرحلة الدراسية', 'المرحله الدراسيه', 'مرحلة', 'مرحله', 'فصل', 'صف', 'class', 'grade');
                const cGender = findCol('النوع', 'الجنس', 'نوع', 'جنس', 'gender');
                const cDob = findCol('تاريخ الميلاد', 'ميلاد');
                const cPhone = findCol('رقم الموبايل', 'موبايل', 'هاتف', 'تليفون', 'phone', 'mobile');
                const cAddr = findCol('محل الاقامة', 'محل الإقامة', 'عنوان', 'address');
                const cFather = findCol('اب الاعتراف', 'أب الاعتراف', 'ولي الامر', 'father');

                if (cName === -1) {
                    alert('⚠️ لم أجد عمود الاسم!\n\nالأعمدة الموجودة في الشيت:\n' + rawHeaders.join('\n'));
                    return;
                }

                // ── Stage override ────────────────────────────────────────────────────────
                const overrideStage = (document.getElementById('import-stage-override') || {}).value || '';

                // ── Stage matching ────────────────────────────────────────────────────────
                const STAGES_NORM = STAGES.map(normAr);
                function matchStage(raw) {
                    if (!raw || !String(raw).trim()) return null;
                    const rn = normAr(raw);
                    if (!rn) return null;
                    let idx;
                    idx = STAGES_NORM.findIndex(x => x === rn); if (idx !== -1) return STAGES[idx];
                    idx = STAGES_NORM.findIndex(x => x.includes(rn) || rn.includes(x)); if (idx !== -1) return STAGES[idx];
                    const nums = { '١': 'اول', '٢': 'ثاني', '٣': 'ثالث', '٤': 'رابع', '٥': 'خامس', '٦': 'سادس', '1': 'اول', '2': 'ثاني', '3': 'ثالث', '4': 'رابع', '5': 'خامس', '6': 'سادس' };
                    for (const [n, w] of Object.entries(nums)) {
                        if (rn.includes(n)) { const t = normAr(rn.replace(new RegExp(n, 'g'), w)); idx = STAGES_NORM.findIndex(x => x.includes(t) || t.includes(x)); if (idx !== -1) return STAGES[idx]; }
                    }
                    const lvls = [['حضانه', 'kg'], ['ابتدائي'], ['اعدادي', 'اعداده'], ['ثانوي']];
                    for (const grp of lvls) { if (grp.some(k => rn.includes(k))) { idx = STAGES_NORM.findIndex(x => grp.some(k => x.includes(k))); if (idx !== -1) return STAGES[idx]; } }
                    return null;
                }

                // ── Gender detection ──────────────────────────────────────────────────────
                function detectGender(row) {
                    if (cGender !== -1) {
                        const g = normAr(String(row[cGender] || ''));
                        if (g.includes('انثي') || g.includes('انثى') || g.includes('بنت') || g === 'f' || g === 'female') return 'أنثى';
                        if (g.includes('ذكر') || g === 'm' || g === 'male') return 'ذكر';
                    }
                    const nm = normAr(String(row[cName] || ''));
                    if (/^(مريم|مارينا|ميرنا|بسنت|ريم|ساره|نوره|نورا|هنا|ايريس|ماريان|ريهام|كرستين)/.test(nm)) return 'أنثى';
                    return 'ذكر';
                }

                // ── Process rows ──────────────────────────────────────────────────────────
                let added = 0, updated = 0, skipped = 0;
                const badStageVals = new Set();
                const dataRows = data.slice(1).filter(r => r && r.length && String(r[cName] || '').trim());

                dataRows.forEach((row) => {
                    const name = String(row[cName] || '').trim();
                    if (!name) return;

                    let validStage = overrideStage;
                    if (!validStage) {
                        const stageRaw = cStage !== -1 ? String(row[cStage] || '').trim() : '';
                        validStage = matchStage(stageRaw) || '';
                        if (!validStage) { badStageVals.add(stageRaw || '(فارغ)'); return; }
                    }

                    const existing = DB.students.find(s => s.name === name && s.stage === validStage);
                    if (existing) {
                        if (forceOverwrite) {
                            // Update existing record
                            if (cDob !== -1 && row[cDob]) existing.dob = String(row[cDob]);
                            if (cPhone !== -1 && row[cPhone]) existing.phone = String(row[cPhone]);
                            if (cAddr !== -1 && row[cAddr]) existing.address = String(row[cAddr]);
                            if (cFather !== -1 && row[cFather]) existing.father = String(row[cFather]);
                            updated++;
                        } else {
                            skipped++;
                        }
                        return;
                    }
                    {
                        const _eStage = validStage, _eYear = DB.schoolYear;
                        const _eCode = generateStudentCode(_eStage, _eYear);
                        DB.students.push({
                            id: 'S' + DB.nextId++, code: _eCode,
                            enrollmentStage: _eStage, enrollmentYear: _eYear,
                            name, stage: validStage,
                            gender: detectGender(row),
                            dob: cDob !== -1 ? String(row[cDob] || '') : '',
                            phone: cPhone !== -1 ? String(row[cPhone] || '') : '',
                            address: cAddr !== -1 ? String(row[cAddr] || '') : '',
                            father: cFather !== -1 ? String(row[cFather] || '') : '',
                            year: DB.schoolYear, status: 'جديد'
                        });
                    }
                    added++;
                });

                // ── Handle stage mismatch: show dialog with mapping option ────────────────
                if (added === 0 && updated === 0 && badStageVals.size > 0 && skipped === 0) {
                    const sample = [...badStageVals].slice(0, 6).join('، ');
                    const nb = document.getElementById('import-no-stage-banner');
                    nb.style.display = 'block';
                    nb.style.background = '#fff0f0';
                    nb.style.borderColor = '#e74c3c';
                    nb.style.color = '#c0392b';
                    nb.innerHTML = `<b>⚠️ المشكلة:</b> قيم المرحلة في الشيت لا تطابق مراحل النظام.<br>
    <b>قيم الشيت:</b> ${sample}<br>
    <b>مراحل النظام:</b> ${STAGES.slice(0, 5).join('، ')}...<br><br>
    <b>👇 الحل: اختر مرحلة من القائمة أعلاه ثم اضغط استيراد مجدداً</b>`;
                    showToast('⚠️ اختر المرحلة يدوياً من القائمة أعلاه');
                    return;
                }

                // ── Handle all duplicates ─────────────────────────────────────────────────
                if (added === 0 && updated === 0 && skipped > 0) {
                    const nb = document.getElementById('import-no-stage-banner');
                    nb.style.display = 'block';
                    nb.style.background = '#fff8e1';
                    nb.style.borderColor = '#f0c040';
                    nb.style.color = '#856404';
                    nb.innerHTML = `ℹ️ الطلاب (${skipped}) موجودون مسبقاً في النظام.<br>
    <button onclick="confirmExcelImportStudents(true)" class="btn btn-danger btn-sm" style="margin-top:8px">🔄 تحديث بيانات الموجودين (${skipped} طالب)</button>`;
                    showToast('ℹ️ كل الطلاب موجودون مسبقاً');
                    return;
                }

                // ── Success ───────────────────────────────────────────────────────────────
                closeModal('modal-excel-import');
                saveDB().then(ok => {
                    renderStudents();
                    renderDashboard();
                    let msg = '✅ تم استيراد ' + added + ' طالب بنجاح';
                    if (updated) msg += ' | تحديث ' + updated;
                    if (skipped) msg += ' | تخطي ' + skipped + ' مكرر';
                    if (badStageVals.size) msg += ' | ⚠️ ' + badStageVals.size + ' صف تجاهل (مرحلة مجهولة)';
                    if (!ok) msg += ' — ⚠️ تحذير: فشل الحفظ!';
                    showToast(msg);
                });

            } catch (err) {
                alert('❌ خطأ في الاستيراد:\n' + err.message + '\n\nStack:\n' + err.stack);
            }
        }
        function confirmExcelImportGrades() {
            if (!_excelGradesData) return;
            const stage = document.getElementById('grade-import-stage').value;
            const term = document.getElementById('grade-import-term').value;
            const filterSubj = (document.getElementById('grade-import-subject') || { value: '' }).value || '';
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            const subjs = DB.subjects[stage] || [];
            // ── Safe-mode + snapshot (auto backup before any write) ──
            const _giAllowOverwrite = !!(document.getElementById('gi-allow-overwrite') || {}).checked;
            const _giCounters = { added: 0, overwritten: 0, skipped: 0 };
            saveGradesSnapshot('grades-import term=' + term + ' stage=' + stage);
            let applied = 0;

            function fuzzyStudent(nm) {
                if (!nm) return null;
                nm = nm.trim();
                let st = students.find(s => s.name === nm); if (st) return st;
                st = students.find(s => s.name.includes(nm) || nm.includes(s.name)); if (st) return st;
                // match on first two words
                const parts = nm.split(' ').slice(0, 2).join(' ');
                return students.find(s => s.name.startsWith(parts)) || null;
            }

            // ── Path A: from AI image analysis ─────────────────────────────────────
            if (_excelGradesData.fromImage && _excelGradesData.rows) {
                _excelGradesData.rows.forEach(row => {
                    const st = fuzzyStudent(row.name); if (!st) return;
                    Object.entries(row.grades || {}).forEach(([subjName, g]) => {
                        if (filterSubj && subjName !== filterSubj) return;
                        ['behavior', 'oral', 'attendance', 'written'].forEach(f => {
                            if (g[f] !== undefined && g[f] !== 0) setGradeSafe(st.id, term, subjName, f, +g[f] || 0, _giAllowOverwrite, _giCounters);
                        });
                        applied++;
                    });
                });
                saveDB().catch(() => showToast('⚠️ فشل الحفظ — جرب مرة أخرى')); closeModal('modal-excel-grades'); renderExamsTable();
                _refreshUndoBtn();
                showImportSummaryToast('من الصورة', _giCounters, _giAllowOverwrite);
                return;
            }

            // ── Path B: from Excel/CSV raw data ────────────────────────────────────
            const data = _excelGradesData.raw || _excelGradesData;
            if (!data || !data.length) return;
            const headers = data[0].map(h => String(h || '').trim());

            // Detect format:
            // Format 1: الاسم | المادة | سلوك | شفوي | حضور | تحريري  (row per subject)
            // Format 2: الاسم | SubjA-سلوك | SubjA-شفوي | SubjB-سلوك ...  (template format)
            // Format 3: الاسم | درجة1 | درجة2 ...  (simple totals per subject column)

            const cName = headers.findIndex(h => h.includes('اسم'));
            const cSubj = headers.findIndex(h => h.includes('ماد'));
            const cBeh = headers.findIndex(h => h.includes('سلوك') && !h.includes(' - '));
            const cOral = headers.findIndex(h => h.includes('شفوي') && !h.includes(' - '));
            const cAtt = headers.findIndex(h => h.includes('حضور') && !h.includes(' - '));
            const cWrit = headers.findIndex(h => h.includes('تحريري') && !h.includes(' - '));

            if (cSubj !== -1 && (cBeh !== -1 || cOral !== -1)) {
                // ── Format 1: one row per student-subject ──
                data.slice(1).forEach(row => {
                    if (!row.length) return;
                    const nm = String(row[cName >= 0 ? cName : 0] || '').trim();
                    const sb = String(row[cSubj] || '').trim();
                    if (!nm || !sb) return;
                    if (filterSubj && sb !== filterSubj) return;
                    const st = fuzzyStudent(nm); if (!st) return;
                    const fmap = { behavior: cBeh, oral: cOral, attendance: cAtt, written: cWrit };
                    Object.entries(fmap).forEach(([f, ci]) => { if (ci !== -1 && String(row[ci] || '').trim() !== '') setGradeSafe(st.id, term, sb, f, parseFloat(row[ci]) || 0, _giAllowOverwrite, _giCounters); });
                    applied++;
                });
            } else {
                // ── Format 2/3: template format  ──
                // Each column after name maps to a subject field
                // Header like "طقس - سلوك (10)" or just "طقس"
                const colMap = [];
                headers.forEach((h, i) => {
                    if (i === (cName >= 0 ? cName : 0)) return;
                    // Try to match "SubjName - field"
                    const dashMatch = h.match(/^(.+?)\s*-\s*(سلوك|شفوي|حضور|تحريري)/);
                    if (dashMatch) {
                        const sn = dashMatch[1].trim().replace(/\s*\(\d+\)/, '');
                        const ft = { 'سلوك': 'behavior', 'شفوي': 'oral', 'حضور': 'attendance', 'تحريري': 'written' }[dashMatch[2]] || 'oral';
                        colMap.push({ i, subj: sn, field: ft }); return;
                    }
                    // Try to match subject name directly
                    const sn = h.replace(/\s*\(\d+\)/, '').replace(/\s*(من|\/)\s*\d+/, '').trim();
                    const found = subjs.find(s => s.name === sn || sn.includes(s.name) || s.name.includes(sn));
                    if (found) colMap.push({ i, subj: found.name, field: 'oral' });
                });
                data.slice(1).forEach(row => {
                    if (!row.length) return;
                    const nm = String(row[cName >= 0 ? cName : 0] || '').trim(); if (!nm) return;
                    const st = fuzzyStudent(nm); if (!st) return;
                    colMap.forEach(({ i, subj, field }) => {
                        if (filterSubj && subj !== filterSubj) return;
                        const val = String(row[i] || '').trim();
                        if (val !== '') setGradeSafe(st.id, term, subj, field, parseFloat(val) || 0, _giAllowOverwrite, _giCounters);
                    });
                    applied++;
                });
            }

            saveDB(); closeModal('modal-excel-grades'); renderExamsTable();
            _refreshUndoBtn();
            showImportSummaryToast('من Excel', _giCounters, _giAllowOverwrite);
        }

        // =========================================================
        // 📷 استيراد الغياب من صور كشوف OCR بالذكاء الاصطناعي
        // =========================================================
        function _getAbsAIProvider() { return (document.getElementById('abs-ai-provider') || { value: 'gemini' }).value; }
        function _getAbsAIKey() {
            const inp = document.getElementById('abs-ai-api-key');
            if (inp && inp.value.trim()) return inp.value.trim();
            return localStorage.getItem('bsh_ai_' + _getAbsAIProvider() + '_key') || '';
        }
        function saveAbsAIKey() {
            const inp = document.getElementById('abs-ai-api-key');
            const k = (inp && inp.value.trim()) || '';
            if (!k) { showToast('⚠️ أدخل المفتاح أولاً'); return; }
            localStorage.setItem('bsh_ai_' + _getAbsAIProvider() + '_key', k);
            showToast('✅ تم حفظ المفتاح على جهازك');
        }
        function onAbsAIProviderChange() {
            const p = _getAbsAIProvider();
            const inp = document.getElementById('abs-ai-api-key');
            if (inp) inp.value = localStorage.getItem('bsh_ai_' + p + '_key') || '';
        }

        function openAbsenceImport() {
            const ss = document.getElementById('abs-import-stage');
            if (ss) {
                const cur = (document.getElementById('abs-stage-sel') || {}).value || '';
                ss.innerHTML = STAGES.map(s => `<option>${s}</option>`).join('');
                if (cur && STAGES.includes(cur)) ss.value = cur;
            }
            const ms = document.getElementById('abs-import-month');
            if (ms) { const curM = (document.getElementById('abs-month-sel') || { value: 9 }).value; ms.value = curM; }
            window._absImagesB64 = [];
            _renderAbsenceThumbs();
            const r = document.getElementById('abs-ai-result'); if (r) r.innerHTML = '';
            const ib = document.getElementById('abs-import-btn'); if (ib) ib.style.display = 'none';
            onAbsAIProviderChange();
            openModal('modal-import-absence');
        }

        async function handleAbsenceImageFiles(e) {
            const files = Array.from(e.target.files || []);
            if (!files.length) return;
            window._absImagesB64 = window._absImagesB64 || [];
            showToast('⏳ جاري ضغط ' + files.length + ' صورة...');
            let done = 0;
            for (const file of files) {
                try {
                    const compressed = await _compressGradeImage(file);
                    window._absImagesB64.push(compressed);
                    done++;
                } catch (err) {
                    const raw = await new Promise(r => { const rd = new FileReader(); rd.onload = ev => r(ev.target.result); rd.readAsDataURL(file); });
                    window._absImagesB64.push({ b64: raw.split(',')[1], mtype: file.type || 'image/jpeg', dataUrl: raw });
                    done++;
                }
            }
            showToast('✅ تم ضغط ' + done + ' صورة بنجاح');
            _renderAbsenceThumbs();
            e.target.value = '';
        }
        function _renderAbsenceThumbs() {
            const el = document.getElementById('abs-image-preview');
            if (!el) return;
            const imgs = window._absImagesB64 || [];
            el.innerHTML = imgs.map((im, i) => `<div style="position:relative"><img src="${im.dataUrl}" style="width:90px;height:90px;object-fit:cover;border-radius:8px;border:2px solid var(--border)"><button onclick="_removeAbsImg(${i})" title="حذف" style="position:absolute;top:-6px;left:-6px;background:#c0392b;color:#fff;border:none;border-radius:50%;width:22px;height:22px;cursor:pointer;font-weight:900;line-height:1">×</button><div style="position:absolute;bottom:2px;right:4px;background:rgba(0,0,0,.6);color:#fff;font-size:10px;border-radius:4px;padding:0 5px">${i + 1}</div></div>`).join('');
            const ab = document.getElementById('abs-ai-analyze-btn');
            if (ab) ab.style.display = imgs.length ? 'inline-flex' : 'none';
            const ib = document.getElementById('abs-import-btn');
            if (ib && !imgs.length) ib.style.display = 'none';
        }
        function _removeAbsImg(i) { (window._absImagesB64 || []).splice(i, 1); _renderAbsenceThumbs(); const r = document.getElementById('abs-ai-result'); if (r) r.innerHTML = ''; }

        async function analyzeAbsenceImagesAI() {
            const imgs = window._absImagesB64 || [];
            if (!imgs.length) { showToast('⚠️ ارفع صورة واحدة على الأقل'); return; }
            const provider = _getAbsAIProvider();
            const key = _getAbsAIKey();
            if (!key) { showToast('⚠️ أدخل مفتاح الـ API أولاً واحفظه'); return; }
            const stage = (document.getElementById('abs-import-stage') || { value: '' }).value;
            if (!stage) { showToast('⚠️ اختر المرحلة أولاً'); return; }
            const month = +((document.getElementById('abs-import-month') || { value: 9 }).value);
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s)).map(s => s.name);
            const subjList = (DB.subjects[stage] || []).map(s => s.name);
            if (!subjList.length) { showToast('⚠️ لا توجد مواد لهذه المرحلة'); return; }
            const year = getSchoolYearForMonth(month);
            let sessions = getSundaysInMonth(year, month).length || 4;
            if (DB && DB.settings && DB.settings.weeklySessionCount) sessions = DB.settings.weeklySessionCount;
            sessions = Math.max(1, Math.min(6, sessions));
            const prompt = `أنت مساعد دقيق لاستخراج بيانات الغياب من كشوف رصد غياب مدرسية مصوّرة (نظام OCR).
في كل ورقة: أسماء الطلاب مطبوعة بوضوح في عمود "اسم الطالب"، وعناوين المواد مطبوعة، وتحت كل مادة أعمدة الحصص (ح1، ح2، ...). داخل كل مربع يكتب المدرس علامة (✗ أو غ أو علامة صح أو أي شخبطة) إذا كان الطالب غائبًا في تلك الحصة لتلك المادة، ويترك المربع فارغًا تمامًا إن كان حاضرًا.

المواد لهذه المرحلة: ${subjList.join('، ')}
عدد الحصص (الأعمدة) لكل مادة: ${sessions} (من ح1 إلى ح${sessions})

أسماء الطلاب المتوقعة (طابِق الأسماء المطبوعة معها حرفيًا قدر الإمكان):
${students.join(' | ')}

اقرأ كل الصور المرفقة (قد تكون عدة صفحات لنفس الكشف) واستخرج لكل طالب أرقام الحصص التي غاب فيها في كل مادة.
أعِد JSON فقط بدون أي نص آخر بهذا الشكل بالضبط:
{"rows":[{"name":"اسم الطالب كما هو مطبوع","absence":{"اسم المادة":[1,3]}}]}

قواعد مهمة:
- داخل المصفوفة ضع أرقام الحصص الغائبة فقط (مثال [1,3] يعني غاب في الحصة 1 والحصة 3).
- إذا حضر الطالب كل الحصص في مادة ما اجعل مصفوفتها فارغة [].
- المربع الفارغ تمامًا = حاضر (لا تضِف رقمه). أي علامة واضحة داخل المربع = غائب.
- لا تتجاوز رقم الحصة ${sessions}.
- استخدم أسماء المواد كما هي مكتوبة أعلاه بالضبط.
- لا تخترع طلابًا غير موجودين، وأدرج كل الطلاب الظاهرين في الصور.`;
            const statusEl = document.getElementById('abs-ai-status');
            const resultEl = document.getElementById('abs-ai-result');
            statusEl.style.display = 'block'; resultEl.innerHTML = '';
            try {
                const text = provider === 'claude' ? await _callClaudeVision(key, prompt, imgs) : await _callGeminiVision(key, prompt, imgs);
                const clean = String(text || '').replace(/```json|```/g, '').trim();
                const parsed = JSON.parse(clean);
                statusEl.style.display = 'none';
                if (!parsed.rows || !parsed.rows.length) { resultEl.innerHTML = '<div style="color:var(--muted);font-size:13px;padding:12px">لم يتم العثور على بيانات غياب — تأكد من وضوح الصور</div>'; return; }
                window._absImportData = { rows: parsed.rows, stage, month, sessions };
                renderAIAbsencePreview(parsed.rows, stage);
            } catch (err) {
                statusEl.style.display = 'none';
                resultEl.innerHTML = '<div style="background:#fee;border:1px solid #fcc;border-radius:10px;padding:12px;color:#c00;font-size:12px">❌ فشل التحليل — ' + (err.message || err) + '<br><small>تأكد من صحة المفتاح، ووضوح الصور، والاتصال بالإنترنت.</small></div>';
            }
        }

        function renderAIAbsencePreview(rows, stage) {
            const resultEl = document.getElementById('abs-ai-result');
            if (!rows || !rows.length) { resultEl.innerHTML = '<div style="color:var(--muted);font-size:13px;padding:12px">لم يتم العثور على بيانات غياب في الصورة</div>'; return; }
            const subjSet = new Set();
            rows.forEach(r => Object.keys(r.absence || {}).forEach(s => subjSet.add(s)));
            const subjs = Array.from(subjSet);
            let totalAbs = 0;
            rows.forEach(r => Object.values(r.absence || {}).forEach(arr => { if (Array.isArray(arr)) totalAbs += arr.length; }));
            let html = `<div style="background:#f0fff4;border:1px solid #b8e6cc;border-radius:10px;padding:10px 14px;font-size:12px;font-weight:700;color:#1a5c2a;margin-bottom:8px">✅ تم استخراج ${rows.length} طالب — إجمالي ${totalAbs} غياب — راجع البيانات ثم اضغط استيراد</div>`;
            html += `<div class="tw"><table><thead><tr><th style="text-align:right">الاسم</th>${subjs.map(s => `<th>${s}</th>`).join('')}</tr></thead><tbody>`;
            rows.slice(0, 10).forEach(r => {
                html += `<tr><td style="text-align:right;font-weight:700;font-size:12px">${r.name}</td>`;
                subjs.forEach(s => { const arr = (r.absence || {})[s] || []; const cnt = Array.isArray(arr) ? arr.length : 0; html += `<td style="font-size:11px;color:${cnt ? '#c0392b' : '#155724'}">${cnt ? '✗ ' + arr.join('،') : '—'}</td>`; });
                html += `</tr>`;
            });
            if (rows.length > 10) html += `<tr><td colspan="${subjs.length + 1}" style="text-align:center;color:var(--muted);font-size:11px">... و ${rows.length - 10} طالب آخر</td></tr>`;
            html += `</tbody></table></div>`;
            resultEl.innerHTML = html;
            const ib = document.getElementById('abs-import-btn'); if (ib) ib.style.display = 'inline-flex';
        }

        function confirmImportAbsence() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط — سجّل دخولك للتعديل'); return; }
            const d = window._absImportData;
            if (!d || !d.rows || !d.rows.length) { showToast('⚠️ لا توجد بيانات للاستيراد'); return; }
            const stage = d.stage, month = d.month;
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            const subjNames = (DB.subjects[stage] || []).map(s => s.name);
            if (!DB.absence) DB.absence = {};

            function normAr(s) {
                return String(s || '').trim()
                    .replace(/[ًٌٍَُِّْ]/g, '')
                    .replace(/[أإآٱ]/g, 'ا')
                    .replace(/[ىئ]/g, 'ي')
                    .replace(/ة/g, 'ه')
                    .replace(/\s+/g, ' ');
            }
            function fuzzyStudent(nm) {
                if (!nm) return null;
                nm = nm.trim();
                let st = students.find(s => s.name === nm); if (st) return st;
                const n = normAr(nm);
                st = students.find(s => normAr(s.name) === n); if (st) return st;
                st = students.find(s => normAr(s.name).includes(n) || n.includes(normAr(s.name))); if (st) return st;
                const parts = n.split(' ').slice(0, 2).join(' ');
                return students.find(s => normAr(s.name).startsWith(parts)) || null;
            }
            function fuzzySubj(sn) {
                if (!sn) return null;
                if (subjNames.includes(sn)) return sn;
                const n = normAr(sn);
                let f = subjNames.find(s => normAr(s) === n); if (f) return f;
                f = subjNames.find(s => normAr(s).includes(n) || n.includes(normAr(s))); if (f) return f;
                return null;
            }

            let applied = 0, marks = 0;
            d.rows.forEach(row => {
                const st = fuzzyStudent(row.name); if (!st) return;
                let touched = false;
                Object.entries(row.absence || {}).forEach(([subjName, weeks]) => {
                    if (!Array.isArray(weeks)) return;
                    const subj = fuzzySubj(subjName); if (!subj) return;
                    const k = `${st.id}_${month}_${subj}`;
                    if (!DB.absence[k]) DB.absence[k] = {};
                    weeks.forEach(w => { const ww = +w; if (ww > 0) { DB.absence[k][ww] = 1; marks++; touched = true; } });
                });
                if (touched) applied++;
            });

            try { _recalcAttendanceForMonth(stage, +month); } catch (e) { }
            saveDB();
            closeModal('modal-import-absence');
            if (typeof renderAbsence === 'function') renderAbsence();
            try { if (typeof renderExamsTable === 'function') renderExamsTable(); } catch (e) { }
            try { logTeacherActivity('غياب', `استيراد غياب من صور OCR — المرحلة: ${stage} | الشهر: ${MONTHS[month] || month} | ${applied} طالب | ${marks} غياب`); } catch (e) { }
            showToast('✅ تم استيراد غياب ' + applied + ' طالب (' + marks + ' علامة غياب) من الصور');
        }


        // =========================================================
        // SUBJECTS
        // =========================================================
        // ── مساعد: ابحث عن المدرسين المسجلين المناسبين لمادة + مرحلة ──
        function _findTeachersForSubject(subjName, stage) {
            const all = _getRegisteredTeachers();
            return all.filter(t => {
                const hasSub = !t.subjects || !t.subjects.length || t.subjects.includes(subjName);
                const hasStage = t.scopeAll !== false || !t.stages || !t.stages.length || t.stages.includes(stage);
                return hasSub && hasStage;
            });
        }

        // ── ملء قائمة مدرسي مادة ──────────────────────────────────
        function _populateSubjTeacherSelect(selId, subjName, stage, currentVal) {
            const sel = document.getElementById(selId);
            if (!sel) return;
            const matched = _findTeachersForSubject(subjName, stage);
            const all = _getRegisteredTeachers();
            // مدرسو المادة أولاً، ثم الباقون
            const matchedNames = new Set(matched.map(t => t.name));
            let html = '<option value="">— اختر مدرساً —</option>';
            if (matched.length) {
                html += `<optgroup label="✅ مناسبون للمادة والمرحلة">`;
                matched.forEach(t => { html += `<option value="${t.name}"${currentVal === t.name ? ' selected' : ''}>${t.name}${t.subjects && t.subjects.length ? ' (' + t.subjects.join('، ') + ')' : ''}</option>`; });
                html += '</optgroup>';
            }
            const others = all.filter(t => !matchedNames.has(t.name));
            if (others.length) {
                html += `<optgroup label="— باقي المدرسين">`;
                others.forEach(t => { html += `<option value="${t.name}"${currentVal === t.name ? ' selected' : ''}>${t.name}</option>`; });
                html += '</optgroup>';
            }
            sel.innerHTML = html;
        }

        function renderSubjects() {
            const stage = document.getElementById('subj-stage-sel').value; if (!stage) return;
            document.getElementById('subj-card-title').textContent = 'مواد مرحلة: ' + stage;
            if (!DB.subjects[stage]) DB.subjects[stage] = [];
            const subjs = DB.subjects[stage];
            const listEl = document.getElementById('subjects-list');
            if (!listEl) return;

            // ── ملء قائمة المدرسين في حقل الإضافة الجديدة ──
            const newSubjNameVal = (document.getElementById('new-subj-name')?.value || '').trim();
            _populateSubjTeacherSelect('new-subj-teacher', newSubjNameVal, stage, document.getElementById('new-subj-teacher')?.value || '');

            if (!subjs.length) {
                listEl.innerHTML = '<span style="color:var(--muted);font-size:13px">لا توجد مواد — أضف مادة من الأسفل</span>';
                return;
            }
            listEl.innerHTML = `<div style="display:flex;flex-direction:column;gap:8px">
    ${subjs.map((s, i) => {
                const total = (s.behavior || 0) + (s.oral || 0) + (s.attendance || 0) + (s.written || 0);
                // ابحث عن مدرسين مناسبين
                const autoTeachers = _findTeachersForSubject(s.name, stage);
                let teacherBadge;
                if (s.teacher) {
                    teacherBadge = `<span style="background:#e8f0ff;color:#1e40af;border:1px solid #93c5fd;border-radius:20px;padding:3px 10px;font-size:11px;font-weight:700">👤 ${s.teacher}</span>`;
                } else if (autoTeachers.length) {
                    const names = autoTeachers.map(t => t.name).join(' / ');
                    teacherBadge = `<span title="مكتشف تلقائياً من المدرسين المسجلين — اضغط تعديل لتأكيد" style="background:#f0fdf4;color:#166534;border:1.5px dashed #86efac;border-radius:20px;padding:3px 10px;font-size:11px;font-weight:700;cursor:help">🔍 ${names}</span>`;
                } else {
                    teacherBadge = '<span style="background:var(--bg);color:var(--muted);border:1px dashed var(--border);border-radius:20px;padding:3px 10px;font-size:11px">لا يوجد مدرس</span>';
                }
                return `<div style="display:flex;align-items:center;gap:10px;padding:10px 14px;background:var(--card);border:1px solid var(--border);border-radius:10px;flex-wrap:wrap">
        <span style="font-size:14px;font-weight:900;color:var(--navy);min-width:90px">${s.name}</span>
        ${teacherBadge}
        <span style="font-size:11px;color:var(--muted);background:var(--bg);border-radius:8px;padding:3px 8px;border:1px solid var(--border)">س:${s.behavior || 0} ش:${s.oral || 0} ح:${s.attendance || 0} ت:${s.written || 0} = <b>${total}</b></span>
        <div style="margin-right:auto;display:flex;gap:6px">
          <button class="btn btn-outline btn-sm" onclick="openEditSubject(${i})">✏️ تعديل</button>
          <button class="btn btn-danger btn-sm" onclick="deleteSubject(${i})">🗑️</button>
        </div>
      </div>`;
            }).join('')}
  </div>`;
        }

        // ── إدارة المدرسين من داخل صفحة المواد ──
        function renderSubjPageTeachers() {
            const cont = document.getElementById('subj-page-teachers-list');
            if (!cont) return;
            const regKey = 'school_registered_teachers_v1';
            if (!DB.registeredTeachers) DB.registeredTeachers = [];
            let lsReg = [];
            try { lsReg = JSON.parse(localStorage.getItem(regKey) || '[]'); } catch (e) { }
            lsReg.forEach(lr => { if (!DB.registeredTeachers.find(r => r.name === lr.name)) DB.registeredTeachers.push(lr); });
            const list = DB.registeredTeachers;
            const cnt = document.getElementById('subj-page-teachers-count');
            if (cnt) cnt.textContent = list.length ? `${list.length} مدرس` : '';
            if (!list.length) {
                cont.innerHTML = `<div style="text-align:center;padding:24px;color:var(--muted);font-size:13px">
      <div style="font-size:36px;margin-bottom:6px">👨‍🏫</div>
      لا يوجد مدرسون — أضف مدرس من الأعلى
    </div>`;
                return;
            }
            cont.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:10px">
    ${list.map(r => {
                const subjs = (r.subjects || []).join('، ') || '—';
                const stages = (r.stages || []).join('، ') || '⚠️ بدون مرحلة';
                const safeName = (r.name || '').replace(/"/g, '&quot;');
                return `<div style="background:#fff;border:1.5px solid var(--border);border-radius:12px;padding:12px 14px;display:flex;flex-direction:column;gap:6px">
        <div style="display:flex;align-items:center;justify-content:space-between;gap:8px">
          <div style="font-size:14px;font-weight:900;color:var(--navy);overflow:hidden;text-overflow:ellipsis">👤 ${r.name}</div>
          <button onclick="deleteTeacherFromSubjPage('${safeName}')" class="btn btn-danger btn-sm" title="حذف المدرس">🗑️</button>
        </div>
        <div style="font-size:11px;color:var(--muted)"><b style="color:#0d5c8a">المواد:</b> ${subjs}</div>
        <div style="font-size:11px;color:var(--muted)"><b style="color:#1a5c2a">المراحل:</b> ${stages}</div>
      </div>`;
            }).join('')}
  </div>`;
        }

        function addTeacherFromSubjPage() {
            if (typeof IS_EDIT_MODE !== 'undefined' && !IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const nameEl = document.getElementById('new-teacher-name');
            const stageEl = document.getElementById('new-teacher-stage');
            const subjEl = document.getElementById('new-teacher-subjects');
            const name = (nameEl?.value || '').trim();
            const stage = (stageEl?.value || '').trim();
            if (!name) { showToast('⚠️ أدخل اسم المدرس'); nameEl?.focus(); return; }
            if (!stage) { showToast('⚠️ اختر المرحلة'); stageEl?.focus(); return; }
            const subjects = (subjEl?.value || '').split(/[،,]/).map(s => s.trim()).filter(Boolean);
            if (!DB.registeredTeachers) DB.registeredTeachers = [];
            let rec = DB.registeredTeachers.find(r => r.name === name);
            if (rec) {
                // موجود — أضف المرحلة والمواد إن لم تكن موجودة
                if (!Array.isArray(rec.stages)) rec.stages = [];
                if (!rec.stages.includes(stage)) rec.stages.push(stage);
                if (subjects.length) {
                    if (!Array.isArray(rec.subjects)) rec.subjects = [];
                    subjects.forEach(s => { if (!rec.subjects.includes(s)) rec.subjects.push(s); });
                }
                rec.scopeAll = false;
                showToast('✅ تم تحديث بيانات المدرس: ' + name);
            } else {
                DB.registeredTeachers.push({
                    name,
                    stages: [stage],
                    subjects,
                    scopeAll: false,
                    registeredAt: new Date().toLocaleDateString('ar-EG')
                });
                showToast('✅ تم إضافة المدرس: ' + name);
            }
            try { localStorage.setItem('school_registered_teachers_v1', JSON.stringify(DB.registeredTeachers)); } catch (e) { }
            if (typeof saveDB === 'function') saveDB();
            if (nameEl) nameEl.value = ''; if (subjEl) subjEl.value = '';
            renderSubjPageTeachers();
            // حدّث قوائم الاختيار في إضافة المادة
            try {
                const st = document.getElementById('subj-stage-sel')?.value;
                const newSubjNameVal = (document.getElementById('new-subj-name')?.value || '').trim();
                if (st) _populateSubjTeacherSelect('new-subj-teacher', newSubjNameVal, st, '');
            } catch (e) { }
        }

        function deleteTeacherFromSubjPage(name) {
            if (!confirm('حذف بيانات المدرس: ' + name + '؟')) return;
            if (!DB.registeredTeachers) DB.registeredTeachers = [];
            DB.registeredTeachers = DB.registeredTeachers.filter(r => r.name !== name);
            try { localStorage.setItem('school_registered_teachers_v1', JSON.stringify(DB.registeredTeachers)); } catch (e) { }
            if (typeof saveDB === 'function') saveDB();
            renderSubjPageTeachers();
            try {
                const st = document.getElementById('subj-stage-sel')?.value;
                const newSubjNameVal = (document.getElementById('new-subj-name')?.value || '').trim();
                if (st) _populateSubjTeacherSelect('new-subj-teacher', newSubjNameVal, st, '');
            } catch (e) { }
            // وحدّث صفحة الإعدادات لو كانت مفتوحة
            if (typeof renderRegisteredTeachers === 'function') { try { renderRegisteredTeachers(); } catch (e) { } }
            showToast('🗑️ تم حذف المدرس: ' + name);
        }

        function openEditSubject(idx) {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const stage = document.getElementById('subj-stage-sel').value;
            const s = (DB.subjects[stage] || [])[idx];
            if (!s) return;
            document.getElementById('edit-subj-name').value = s.name || '';
            // ملء القائمة الذكية للمدرسين
            _populateSubjTeacherSelect('edit-subj-teacher', s.name, stage, s.teacher || '');
            document.getElementById('edit-subj-beh').value = s.behavior || 0;
            document.getElementById('edit-subj-oral').value = s.oral || 0;
            document.getElementById('edit-subj-att').value = s.attendance || 0;
            document.getElementById('edit-subj-writ').value = s.written || 0;
            document.getElementById('edit-subj-stage').value = stage;
            document.getElementById('edit-subj-idx').value = idx;
            const sub = document.getElementById('edit-subj-modal-sub');
            if (sub) sub.textContent = stage + ' — ' + s.name;
            updateEditTotal();
            openModal('modal-edit-subject');
        }
        function updateEditTotal() {
            const total = (+document.getElementById('edit-subj-beh').value || 0)
                + (+document.getElementById('edit-subj-oral').value || 0)
                + (+document.getElementById('edit-subj-att').value || 0)
                + (+document.getElementById('edit-subj-writ').value || 0);
            const badge = document.getElementById('edit-subj-total-badge');
            if (badge) badge.textContent = 'المجموع: ' + total;
        }
        function saveEditSubject() {
            if (!IS_EDIT_MODE) return;
            const stage = document.getElementById('edit-subj-stage').value;
            const idx = +document.getElementById('edit-subj-idx').value;
            const s = (DB.subjects[stage] || [])[idx];
            if (!s) return;
            const newName = document.getElementById('edit-subj-name').value.trim();
            if (!newName) { showToast('⚠️ أدخل اسم المادة'); return; }
            s.name = newName;
            s.teacher = (document.getElementById('edit-subj-teacher').value || '').trim();
            s.behavior = +document.getElementById('edit-subj-beh').value || 0;
            s.oral = +document.getElementById('edit-subj-oral').value || 0;
            s.attendance = +document.getElementById('edit-subj-att').value || 0;
            s.written = +document.getElementById('edit-subj-writ').value || 0;
            saveDB().catch(() => showToast('⚠️ فشل الحفظ — جرب مرة أخرى')); closeModal('modal-edit-subject'); renderSubjects(); showToast('✅ تم تحديث المادة');
        }
        function addSubject() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const stage = document.getElementById('subj-stage-sel').value; const name = document.getElementById('new-subj-name').value.trim();
            if (!name) { showToast('⚠️ أدخل اسم المادة'); return; }
            if (!DB.subjects[stage]) DB.subjects[stage] = [];
            if (DB.subjects[stage].find(s => s.name === name)) { showToast('⚠️ المادة موجودة'); return; }
            const teacher = (document.getElementById('new-subj-teacher').value || '').trim();
            DB.subjects[stage].push({ name, teacher, behavior: +document.getElementById('ns-beh').value || 0, oral: +document.getElementById('ns-oral').value || 0, attendance: +document.getElementById('ns-att').value || 0, written: +document.getElementById('ns-writ').value || 0 });
            saveDB().catch(() => showToast('⚠️ فشل الحفظ — جرب مرة أخرى')); document.getElementById('new-subj-name').value = ''; document.getElementById('new-subj-teacher').value = ''; renderSubjects(); showToast('✅ تمت إضافة: ' + name);
        }
        function deleteSubject(idx) {
            if (!IS_EDIT_MODE) return;
            if (IS_TEACHER_MODE) { showToast('⚠️ غير مسموح — للأدمن فقط'); return; }
            const stage = document.getElementById('subj-stage-sel').value;
            if (!confirm('حذف المادة؟')) return; DB.subjects[stage].splice(idx, 1); saveDB().catch(() => showToast('⚠️ فشل الحفظ')); renderSubjects();
        }

        // =========================================================
        // GRADES
        // =========================================================
        function getGrade(sid, term, subj, field) { const g = DB.grades[sid + '_t' + term + '_' + subj]; return g ? (g[field] || 0) : 0; }

        // =========================================================
        // تقرير الرصد الشامل
        // =========================================================
        function renderGradesReport() {
            const term = document.getElementById('report-term-sel')?.value || '1';
            const summaryEl = document.getElementById('report-summary');
            const bodyEl = document.getElementById('report-body');
            if (!summaryEl || !bodyEl) return;

            summaryEl.innerHTML = '';

            const rows = [];
            STAGES.forEach(stage => {
                const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
                const subjects = DB.subjects[stage] || [];
                if (!students.length || !subjects.length) return;
                subjects.forEach(subj => {
                    let rased = 0;
                    students.forEach(st => {
                        const g = DB.grades[st.id + '_t' + term + '_' + subj.name];
                        const hasData = g && ((subj.behavior && (g.behavior || 0) > 0) || (subj.oral && (g.oral || 0) > 0) || (subj.attendance && (g.attendance || 0) > 0) || (subj.written && (g.written || 0) > 0));
                        if (hasData) rased++;
                    });
                    rows.push({ stage, subj: subj.name, total: students.length, rased, notRased: students.length - rased });
                });
            });

            if (!rows.length) {
                bodyEl.innerHTML = '<div style="text-align:center;padding:40px;color:var(--muted)">لا يوجد بيانات</div>';
                return;
            }

            bodyEl.innerHTML = `
    <div class="card" style="padding:0;overflow:hidden">
      <table style="width:100%;border-collapse:collapse;font-family:'Cairo',sans-serif;font-size:13px">
        <thead>
          <tr style="background:var(--navy);color:#fff">
            <th style="padding:10px 14px;text-align:right;font-weight:700">المرحلة</th>
            <th style="padding:10px 14px;text-align:right;font-weight:700">المادة</th>
            <th style="padding:10px 14px;text-align:center;font-weight:700">✅ اترصدوا</th>
            <th style="padding:10px 14px;text-align:center;font-weight:700">❌ لسه</th>
            <th style="padding:10px 14px;text-align:center;font-weight:700">الحالة</th>
          </tr>
        </thead>
        <tbody>
          ${rows.map((r, i) => `
            <tr style="background:${i % 2 === 0 ? 'var(--card)' : 'var(--bg)'};border-bottom:1px solid var(--border)">
              <td style="padding:9px 14px;font-weight:700;color:var(--navy)">${r.stage}</td>
              <td style="padding:9px 14px;color:var(--text)">${r.subj}</td>
              <td style="padding:9px 14px;text-align:center;font-weight:700;color:#1a5c2a">${r.rased}</td>
              <td style="padding:9px 14px;text-align:center;font-weight:700;color:${r.notRased > 0 ? '#c0392b' : '#1a5c2a'}">${r.notRased}</td>
              <td style="padding:9px 14px;text-align:center">
                ${r.notRased === 0
                    ? '<span style="background:#e8f5e9;color:#1a5c2a;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:700">مكتمل ✅</span>'
                    : r.rased === 0
                        ? '<span style="background:#ffebee;color:#c0392b;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:700">لم يبدأ ❌</span>'
                        : '<span style="background:#fff8e1;color:#9a7a1a;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:700">ناقص ⚠️</span>'
                }
              </td>
            </tr>`
            ).join('')}
        </tbody>
      </table>
    </div>`;
        }

        function setGrade(sid, term, subj, field, val) { const k = sid + '_t' + term + '_' + subj; if (!DB.grades[k]) DB.grades[k] = {}; DB.grades[k][field] = val; }
        // ── Safe-mode grade writer + snapshot/undo for grade imports ──
        function setGradeSafe(sid, term, subj, field, val, allowOverwrite, counters) {
            counters = counters || { added: 0, overwritten: 0, skipped: 0 };
            const k = sid + '_t' + term + '_' + subj;
            const cur = DB.grades && DB.grades[k] ? DB.grades[k][field] : undefined;
            const hasValue = cur !== undefined && cur !== null && cur !== '' && (+cur > 0);
            if (hasValue && !allowOverwrite) { counters.skipped++; return false; }
            if (hasValue && allowOverwrite) counters.overwritten++; else counters.added++;
            if (!DB.grades) DB.grades = {};
            if (!DB.grades[k]) DB.grades[k] = {};
            DB.grades[k][field] = val;
            return true;
        }
        function saveGradesSnapshot(reason) {
            try {
                const snap = { takenAt: Date.now(), reason: reason || 'grades-import', grades: JSON.parse(JSON.stringify(DB.grades || {})) };
                try { localStorage.setItem('grades_backup_last', JSON.stringify(snap)); } catch (e) { console.warn('localStorage snapshot failed', e); }
                const d = new Date();
                const pad = n => String(n).padStart(2, '0');
                const ts = d.getFullYear() + '-' + pad(d.getMonth() + 1) + '-' + pad(d.getDate()) + '-' + pad(d.getHours()) + pad(d.getMinutes());
                const blob = new Blob([JSON.stringify(snap, null, 2)], { type: 'application/json' });
                const a = document.createElement('a');
                a.href = URL.createObjectURL(blob);
                a.download = 'grades-backup-' + ts + '.json';
                document.body.appendChild(a); a.click();
                setTimeout(() => { try { URL.revokeObjectURL(a.href); a.remove(); } catch (e) {} }, 1000);
            } catch (e) { console.error('saveGradesSnapshot failed', e); }
        }
        function _refreshUndoBtn() {
            const btn = document.getElementById('undo-grades-import-btn');
            if (!btn) return;
            const has = !!localStorage.getItem('grades_backup_last');
            btn.disabled = !has;
            btn.style.opacity = has ? '1' : '.5';
            btn.style.cursor = has ? 'pointer' : 'not-allowed';
        }
        function undoLastGradesImport() {
            if (typeof IS_EDIT_MODE !== 'undefined' && !IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const raw = localStorage.getItem('grades_backup_last');
            if (!raw) { showToast('⚠️ مفيش نسخة احتياطية للاستيراد السابق'); return; }
            let snap;
            try { snap = JSON.parse(raw); } catch (e) { showToast('❌ النسخة الاحتياطية تالفة'); return; }
            const when = snap && snap.takenAt ? new Date(snap.takenAt).toLocaleString('ar-EG') : '';
            if (!confirm('هترجع كل الدرجات لحالتها قبل آخر استيراد' + (when ? ' (' + when + ')' : '') + '.\nمتأكد؟')) return;
            DB.grades = snap.grades || {};
            const done = () => {
                try { localStorage.removeItem('grades_backup_last'); } catch (e) {}
                _refreshUndoBtn();
                if (typeof renderExamsTable === 'function') renderExamsTable();
                showToast('↩️ تم التراجع — رجعت الدرجات لحالة ما قبل الاستيراد');
            };
            const r = saveDB && saveDB();
            if (r && typeof r.then === 'function') r.then(done).catch(done); else done();
        }
        function onGiOverwriteToggle() {
            const cb = document.getElementById('gi-allow-overwrite');
            const warn = document.getElementById('gi-overwrite-warn');
            const box = document.getElementById('gi-safe-box');
            if (!cb) return;
            if (cb.checked) {
                if (warn) warn.style.display = 'block';
                if (box) { box.style.borderColor = '#dc2626'; box.style.background = '#fef2f2'; }
            } else {
                if (warn) warn.style.display = 'none';
                if (box) { box.style.borderColor = '#16a34a'; box.style.background = '#f0fdf4'; }
            }
        }
        function showImportSummaryToast(label, c, allowOverwrite) {
            c = c || { added: 0, overwritten: 0, skipped: 0 };
            let msg = '✅ استيراد ' + (label || '') + ' — مضاف: ' + c.added;
            if (allowOverwrite) msg += ' | مستبدل: ' + c.overwritten;
            if (c.skipped) msg += ' | متخطى (Safe Mode): ' + c.skipped;
            msg += ' — اضغط "↩️ تراجع" لو محتاج ترجع.';
            showToast(msg);
        }
        // Refresh undo button on page load
        try { if (typeof window !== 'undefined') window.addEventListener('load', function(){ try { _refreshUndoBtn(); } catch(e){} }); } catch(e){}
        function calcSubjTotal(sid, term, subj) { return getGrade(sid, term, subj, 'behavior') + getGrade(sid, term, subj, 'oral') + getGrade(sid, term, subj, 'attendance') + getGrade(sid, term, subj, 'written'); }
        function getSubjMax(subj, stage) { const s = (DB.subjects[stage] || []).find(x => x.name === subj); if (!s) return 0; return (s.behavior || 0) + (s.oral || 0) + (s.attendance || 0) + (s.written || 0); }
        function calcTotal(sid, term, stage) { return (DB.subjects[stage] || []).reduce((sum, s) => sum + calcSubjTotal(sid, term, s.name), 0); }
        function getTermMax(stage) { return (DB.subjects[stage] || []).reduce((sum, s) => (s.behavior || 0) + (s.oral || 0) + (s.attendance || 0) + (s.written || 0) + sum, 0); }

        // =========================================================
        // 🎯 درجة الحضور التلقائية من سجل الغياب
        // =========================================================
        // ترجع توزيع شهور كل ترم (قابل للتعديل من الإعدادات)
        function _attTermMonths() {
            const s = (DB.settings || {});
            const def = { 1: [9, 10, 11, 12, 1], 2: [2, 3, 4], 3: [5, 6] };
            const parse = (v, d) => {
                if (!v && v !== 0) return d;
                const arr = String(v).split(/[،,\s]+/).map(x => parseInt(x, 10)).filter(x => x >= 1 && x <= 12);
                return arr.length ? arr : d;
            };
            return {
                1: parse(s.attT1, def[1]),
                2: parse(s.attT2, def[2]),
                3: parse(s.attT3, def[3])
            };
        }
        // عدد الحصص (الآحاد) في شهر معيّن
        function _sessionsInMonth(month) {
            if (DB && DB.settings && DB.settings.weeklySessionCount) return DB.settings.weeklySessionCount;
            const year = getSchoolYearForMonth(month);
            const n = getSundaysInMonth(year, month).length;
            return n || 4;
        }
        // يحسب درجة الحضور لمادة/ترم من سجل الغياب ودرجة الحضور القصوى للمادة
        function computeAttendanceGrade(sid, term, subjName, attMax) {
            if (!attMax || attMax <= 0) return 0;
            const months = (_attTermMonths()[+term]) || [];
            if (!months.length) return attMax;
            let total = 0, absent = 0;
            months.forEach(m => {
                const sessions = _sessionsInMonth(m);
                total += sessions;
                const rec = (DB.absence || {})[`${sid}_${m}_${subjName}`] || {};
                for (let w = 1; w <= sessions; w++) if (rec[w]) absent++;
            });
            if (total <= 0) return attMax;
            const present = Math.max(0, total - absent);
            let g = attMax * (present / total);
            g = Math.round(g * 2) / 2; // تقريب لأقرب نصف درجة
            return Math.max(0, Math.min(attMax, g));
        }
        // يطبّق الحساب ويخزّنه في DB.grades لمرحلة + ترم محددين
        function applyAutoAttendanceForStageTerm(stage, term) {
            if (!DB.settings || !DB.settings.autoAttendanceEnabled) return 0;
            const subjs = (DB.subjects[stage] || []).filter(s => (s.attendance || 0) > 0);
            if (!subjs.length) return 0;
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            let n = 0;
            students.forEach(st => {
                subjs.forEach(s => {
                    const k = st.id + '_t' + term + '_' + s.name;
                    if (!DB.grades[k]) DB.grades[k] = {};
                    if (DB.grades[k].attendanceManual === undefined) {
                        DB.grades[k].attendanceManual = DB.grades[k].attendance || 0;
                    }
                    const g = computeAttendanceGrade(st.id, term, s.name, s.attendance);
                    setGrade(st.id, term, s.name, 'attendance', g);
                    n++;
                });
            });
            return n;
        }
        // يعيد درجات الحضور اليدوية المحفوظة عند تعطيل الحساب التلقائي
        function restoreManualAttendance() {
            let n = 0;
            Object.keys(DB.grades || {}).forEach(k => {
                const g = DB.grades[k];
                if (g && g.attendanceManual !== undefined) {
                    g.attendance = g.attendanceManual;
                    delete g.attendanceManual;
                    n++;
                }
            });
            return n;
        }
        // يعيد حساب درجات الحضور لكل المراحل وكل الترمات
        function recomputeAllAttendance(silent) {
            if (!DB.settings || !DB.settings.autoAttendanceEnabled) { if (!silent) showToast('⚠️ فعّل «حساب الحضور التلقائي» من الإعدادات أولاً'); return 0; }
            const terms = [1, 2, 3].slice(0, (DB.settings.termsCount || 3));
            let n = 0;
            STAGES.forEach(stage => { terms.forEach(t => { n += applyAutoAttendanceForStageTerm(stage, String(t)); }); });
            return n;
        }
        // زر الحساب اليدوي (من الإعدادات أو صفحة الدرجات)
        function recalcAttendanceNow() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            if (!DB.settings || !DB.settings.autoAttendanceEnabled) { showToast('⚠️ فعّل «حساب الحضور التلقائي» من الإعدادات أولاً'); return; }
            const n = recomputeAllAttendance(true);
            saveDB().then(() => {
                try { if (typeof renderExamsTable === 'function') renderExamsTable(); } catch (e) { }
                try { logTeacherActivity('درجات', `حساب درجات الحضور تلقائيًا من الغياب (${n} سجل)`); } catch (e) { }
            });
            showToast('✅ تم حساب درجات الحضور من الغياب (' + n + ' سجل)');
        }
        // إعادة حساب الحضور للترم الذي يقع فيه شهر معيّن (يُستدعى بعد تعديل الغياب)
        function _recalcAttendanceForMonth(stage, month) {
            if (!DB.settings || !DB.settings.autoAttendanceEnabled) return;
            const map = _attTermMonths();
            [1, 2, 3].forEach(t => { if ((map[t] || []).includes(+month)) applyAutoAttendanceForStageTerm(stage, String(t)); });
        }
        function getGradeText(pct) { const s = DB.settings; if (pct >= s.exPct) return 'ممتاز'; if (pct >= s.vgPct) return 'جيد جداً'; if (pct >= s.gPct) return 'جيد'; if (pct >= s.passPct) return 'مقبول'; return 'راسب'; }
        function getGradeClass(pct) { const s = DB.settings; if (pct >= s.vgPct) return 'b-success'; if (pct >= s.passPct) return 'b-warn'; return 'b-danger'; }
        function getGradeColor(pct) { const s = DB.settings; if (pct >= s.exPct) return '#15803d'; if (pct >= s.vgPct) return '#166534'; if (pct >= s.gPct) return '#0c5460'; if (pct >= s.passPct) return '#856404'; return '#991b1b'; }
        // =========================================================
        // MERCY GRADE (درجة الرأفة التلقائية)
        // =========================================================
        function applyMercyGrade(rawTotal, maxGrade) {
            if (!DB.settings.mercyEnabled || maxGrade <= 0) return rawTotal;
            const mercyMax = DB.settings.mercyMax || 1;
            const passPct = DB.settings.passPct || 50;
            const passThreshold = maxGrade * passPct / 100; // e.g. 50 out of 100
            const diff = passThreshold - rawTotal;
            // Case 1: close to passing
            if (diff > 0 && diff <= mercyMax) return passThreshold;
            // Case 2: close to full marks
            const diffToFull = maxGrade - rawTotal;
            if (rawTotal >= passThreshold && diffToFull > 0 && diffToFull <= mercyMax) return maxGrade;
            return rawTotal;
        }
        function getMercyInfo(rawTotal, maxGrade) {
            if (!DB.settings.mercyEnabled || maxGrade <= 0) return null;
            const adjusted = applyMercyGrade(rawTotal, maxGrade);
            if (adjusted !== rawTotal) {
                return { original: rawTotal, adjusted: adjusted, added: +(adjusted - rawTotal).toFixed(1) };
            }
            return null;
        }


        function renderQuickReport(term) {
            const el = document.getElementById('quick-report-strip');
            if (!el) return;
            const rows = [];
            STAGES.forEach(stage => {
                const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
                const subjects = DB.subjects[stage] || [];
                if (!students.length || !subjects.length) return;
                let allDone = true, noneDone = true;
                subjects.forEach(subj => {
                    let rased = 0;
                    students.forEach(st => {
                        const g = DB.grades[st.id + '_t' + term + '_' + subj.name];
                        const has = g && ((subj.behavior && (g.behavior || 0) > 0) || (subj.oral && (g.oral || 0) > 0) || (subj.attendance && (g.attendance || 0) > 0) || (subj.written && (g.written || 0) > 0));
                        if (has) rased++;
                    });
                    if (rased < students.length) allDone = false;
                    if (rased > 0) noneDone = false;
                });
                const status = allDone ? 'done' : noneDone ? 'empty' : 'partial';
                rows.push({ stage, status });
            });
            if (!rows.length) { el.innerHTML = ''; return; }
            const termLabel = ['', 'الترم الأول', 'الترم الثاني', 'الترم الثالث'][+term] || '';
            el.innerHTML = `
    <div style="background:var(--card);border:1px solid var(--border);border-radius:14px;padding:14px 18px">
      <div style="font-size:11px;font-weight:700;color:var(--muted);margin-bottom:10px">📋 حالة الرصد — ${termLabel}</div>
      <div style="display:flex;flex-wrap:wrap;gap:8px">
        ${rows.map(r => {
                const cfg = r.status === 'done'
                    ? { bg: '#e8f5e9', border: '#a8d5b5', color: '#1a5c2a', icon: '✅' }
                    : r.status === 'empty'
                        ? { bg: '#ffebee', border: '#ffcdd2', color: '#c0392b', icon: '❌' }
                        : { bg: '#fff8e1', border: '#f0c040', color: '#9a7a1a', icon: '⚠️' };
                return `<div style="background:${cfg.bg};border:1px solid ${cfg.border};border-radius:20px;padding:5px 13px;font-size:12px;font-weight:700;color:${cfg.color};white-space:nowrap">${cfg.icon} ${r.stage}</div>`;
            }).join('')}
      </div>
    </div>`;
        }

        function renderExamsTable() {
            const stage = (document.getElementById('exam-stage-sel') || { value: STAGES[0] }).value;
            const term = (document.getElementById('exam-term-sel') || { value: '1' }).value;
            renderQuickReport(term);
            const q = ((document.getElementById('exam-search') || {}).value || '').toLowerCase();
            const subjs = DB.subjects[stage] || []; const students = _sortStudentsForPrint(DB.students.filter(s => s.stage === stage && !isGraduate(s) && (!q || s.name.toLowerCase().includes(q))), stage, term);
            const cntEl = document.getElementById('exam-student-count'); if (cntEl) cntEl.textContent = DB.students.filter(s => s.stage === stage && !isGraduate(s)).length + ' طالب';
            const thead = document.getElementById('exams-thead'), tbody = document.getElementById('exams-tbody'), statsBar = document.getElementById('exams-stats-bar');
            if (!subjs.length) { thead.innerHTML = ''; tbody.innerHTML = `<tr><td colspan="2" style="padding:24px;text-align:center;color:var(--muted)">⚠️ لا توجد مواد — اذهب لـ "إدارة المواد" أولاً</td></tr>`; statsBar.innerHTML = ''; return; }
            { const _rab = document.getElementById('recalc-att-btn'); if (_rab) _rab.style.display = (DB.settings && DB.settings.autoAttendanceEnabled) ? '' : 'none'; }
            if (DB.settings && DB.settings.autoAttendanceEnabled) applyAutoAttendanceForStageTerm(stage, term);
            const termMax = getTermMax(stage), withG = students.filter(st => calcTotal(st.id, term, stage) > 0).length;
            // حساب الأوائل والراسبين
            const scored = students.map(st => { const rawT = calcTotal(st.id, term, stage), max = getTermMax(stage), t = applyMercyGrade(rawT, max), pct = max > 0 ? t / max * 100 : 0; return { id: st.id, pct, rawT }; }).filter(s => s.rawT > 0).sort((a, b) => b.pct - a.pct);
            const firstId = scored.length ? scored[0].id : null;
            const passedIds = new Set(scored.filter(s => s.pct >= (DB.settings.passPct || 50)).map(s => s.id));
            const failedCount = students.filter(st => { const rawT = calcTotal(st.id, term, stage), max = getTermMax(stage), t = applyMercyGrade(rawT, max), pct = max > 0 ? t / max * 100 : 0; return rawT > 0 && pct < (DB.settings.passPct || 50); }).length;
            statsBar.innerHTML = `<div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:var(--navy)">📋 ${students.length} طالب</div><div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:var(--green)">✅ ${withG} تم رصدهم</div><div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:var(--muted)">📊 أقصى: ${termMax}</div>${firstId ? `<div style="background:linear-gradient(135deg,#fff8e1,#fef3c7);border:1px solid #fbbf24;border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:#92400e">🥇 الأول: ${students.find(s => s.id === firstId)?.name || ''}</div>` : ''}${failedCount ? `<div style="background:linear-gradient(135deg,#fff0f0,#fde8e8);border:1px solid #fca5a5;border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:#991b1b">❌ راسب: ${failedCount}</div>` : '<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);border:1px solid #86efac;border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:#166534">✔️ لا يوجد رسوب</div>'}`;
            const fmap = { behavior: 'سلوك', oral: 'شفوي', attendance: 'حضور', written: 'تحريري' };
            let thH = `<tr><th style="min-width:150px;text-align:right;padding-right:14px;position:sticky;right:0;z-index:3;background:linear-gradient(135deg,var(--navy),var(--navy-light))">الطالب</th>`;
            subjs.forEach(s => { const flds = ['behavior', 'oral', 'attendance', 'written'].filter(f => s[f] > 0); if (flds.length) thH += `<th colspan="${flds.length + 1}" style="border-left:2px solid rgba(255,255,255,.2)">${s.name}<div style="font-size:10px;opacity:.7;font-weight:400">من ${getSubjMax(s.name, stage)}</div></th>`; });
            thH += `<th>المجموع</th><th>النسبة</th><th>التقدير</th></tr>`;
            thH += `<tr><th style="text-align:right;padding-right:14px;font-size:10px;position:sticky;right:0;z-index:3;background:#1a3a5c">الاسم</th>`;
            subjs.forEach(s => { const flds=['behavior','oral','attendance','written'].filter(f=>s[f]>0); flds.forEach(f => { thH += `<th style="font-size:10px;border-left:1px solid rgba(255,255,255,.1)">${fmap[f]}<br><span style="font-weight:400">/${s[f]}</span></th>`; }); if(flds.length) thH += `<th style="font-size:10px;border-left:2px solid rgba(255,215,0,.5);background:rgba(255,215,0,.18);color:#fff;font-weight:900">مجموع<br><span style="font-weight:400;color:rgba(255,255,255,.8)">/${getSubjMax(s.name,stage)}</span></th>`; });
            thH += `<th></th><th></th><th></th></tr>`; thead.innerHTML = thH;
            if (!students.length) { tbody.innerHTML = `<tr><td colspan="20" style="padding:24px;text-align:center;color:var(--muted)">لا يوجد طلاب</td></tr>`; return; }
            tbody.innerHTML = students.map(st => {
                const rawTotal = calcTotal(st.id, term, stage), max = getTermMax(stage), total = applyMercyGrade(rawTotal, max), pct = max > 0 ? total / max * 100 : 0;
                const mercyInfo = getMercyInfo(rawTotal, max);
                const isFirst = st.id === firstId;
                const isFailed = rawTotal > 0 && pct < (DB.settings.passPct || 50);
                const isRepeater = (st.status || '').indexOf('راسب') !== -1;
            const rowBg = isFirst ? 'background:linear-gradient(135deg,#fffde7,#fef9c3)' : isFailed ? 'background:linear-gradient(135deg,#fff5f5,#fee2e2)' : isRepeater ? 'background:linear-gradient(135deg,#fef3c7,#fde68a)' : '';
                let row = `<tr style="${rowBg}"><td class="sticky-col" style="${isFirst ? 'background:linear-gradient(135deg,#fffde7,#fef9c3);' : isFailed ? 'background:linear-gradient(135deg,#fff5f5,#fee2e2);' : ''}">${isFirst ? '🥇 ' : isFailed ? '❌ ' : ''}${(st.status || '').indexOf('راسب') !== -1 ? '🔄 ' : ''}${st.name}</td>`;
                const _autoAtt = !!(DB.settings && DB.settings.autoAttendanceEnabled);
                subjs.forEach(s => { const flds=['behavior','oral','attendance','written'].filter(f=>s[f]>0); flds.forEach(f => { const val=getGrade(st.id,term,s.name,f); const cls=val>s[f]?' over':val>0?' filled':''; if(_autoAtt && f==='attendance'){ row += `<td style="border-left:1px solid rgba(212,192,138,.2)"><input type="number" class="gi auto-att${val>0?' filled':''}" readonly tabindex="-1" value="${val||''}" placeholder="—" title="تُحسب تلقائيًا من سجل الغياب — معطّلة للتعديل اليدوي" data-sid="${st.id}" data-term="${term}" data-subj="${s.name}" data-field="${f}" data-max="${s[f]}" style="background:#eef6ee;color:#15803d;font-weight:800;cursor:not-allowed"></td>`; } else { row += `<td style="border-left:1px solid rgba(212,192,138,.2)"><input type="number" class="gi${cls}" min="0" max="${s[f]}" value="${val||''}" placeholder="—" data-sid="${st.id}" data-term="${term}" data-subj="${s.name}" data-field="${f}" data-max="${s[f]}" oninput="handleGradeInput(this)" onchange="handleGradeInput(this)"></td>`; } }); if(flds.length){ const sTotal=calcSubjTotal(st.id,term,s.name),sMax=getSubjMax(s.name,stage),sPct=sMax>0?sTotal/sMax*100:0,sSafeKey=s.name.replace(/\s/g,'_'); row += `<td id="sc-${st.id}-${term}-${sSafeKey}" style="border-left:2px solid rgba(255,215,0,.35);background:rgba(255,215,0,.07);text-align:center;white-space:nowrap;padding:4px 10px;min-width:60px"><span style="font-size:13px;font-weight:900;color:${sTotal>0?getGradeColor(sPct):'var(--muted)'}">${sTotal||'—'}</span><span style="font-size:10px;color:var(--muted);font-weight:400">/${sMax}</span></td>`; } });
                row += `<td class="grade-total-cell" id="tc-${st.id}-${term}">${total}<span style="font-size:10px;color:var(--muted);font-weight:400">/${max}</span>${mercyInfo ? '<span style="font-size:9px;color:#d97706;font-weight:700" title="درجة رأفة: +' + mercyInfo.added + '"> \u{1F3AF}+' + mercyInfo.added + '</span>' : ''}</td><td id="tp-${st.id}-${term}"><span style="font-size:13px;font-weight:900;color:${getGradeColor(pct)}">${pct.toFixed(1)}%</span></td><td id="tg-${st.id}-${term}"><span class="badge ${getGradeClass(pct)}">${getGradeText(pct)}</span></td>`;
                const hasN = spGetNotesCount(st.id) > 0;
                row += `<td style="white-space:nowrap"><button class="btn btn-sm allow-ro" style="background:${hasN ? '#e8f0ff' : 'var(--bg)'};color:${hasN ? '#1e40af' : 'var(--muted)'};border:1.5px solid ${hasN ? '#93c5fd' : 'var(--border)'};font-size:12px" title="${hasN ? 'يوجد ملاحظات — انقر للعرض' : 'أضف ملاحظة'}" onclick="openSPNotes('${st.id}')">${hasN ? '📝' : '📋'}</button> <button class="btn btn-danger btn-sm" title="حذف درجات هذا الطالب في هذا الترم" onclick="deleteStudentTermGrades('${st.id}','${term}','${stage}')">🗑️</button></td></tr>`;
                return row;
            }).join('');
        }
        let _gradeAutoSaveTimer = null;
        function handleGradeInput(el) {
            if (!IS_EDIT_MODE) { el.value = getGrade(el.dataset.sid, el.dataset.term, el.dataset.subj, el.dataset.field) || ''; return; }
            const sid = el.dataset.sid, term = el.dataset.term, subj = el.dataset.subj, field = el.dataset.field, max = +el.dataset.max;
            let val = parseFloat(el.value) || 0;
            if (val < 0) { val = 0; el.value = 0; }
            if (val > max) {
                val = max;
                el.value = max;
                showToast('⚠️ الحد الأقصى لهذه المادة هو ' + max);
            }
            setGrade(sid, term, subj, field, val);
            el.className = 'gi' + (val > 0 ? ' filled' : '');
            const stage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            const rawTotal = calcTotal(sid, term, stage), termMax = getTermMax(stage);
            const total = applyMercyGrade(rawTotal, termMax);
            const pct = termMax > 0 ? total / termMax * 100 : 0;
            const mercyInfo = getMercyInfo(rawTotal, termMax);
            const tc = document.getElementById('tc-' + sid + '-' + term), tp = document.getElementById('tp-' + sid + '-' + term), tg = document.getElementById('tg-' + sid + '-' + term);
            if (tc) tc.innerHTML = `${total}<span style="font-size:10px;color:var(--muted);font-weight:400">/${termMax}</span>${mercyInfo ? '<span style="font-size:9px;color:#d97706;font-weight:700" title="درجة رأفة: +' + mercyInfo.added + '"> \u{1F3AF}+' + mercyInfo.added + '</span>' : ''}`;
            if (tp) tp.innerHTML = `<span style="font-size:13px;font-weight:900;color:${getGradeColor(pct)}">${pct.toFixed(1)}%</span>`;
            if (tg) tg.innerHTML = `<span class="badge ${getGradeClass(pct)}">${getGradeText(pct)}</span>`;
            // ✅ تحديث مجموع المادة لحظياً
            const sSafeKey = subj.replace(/\s/g,'_');
            const sc = document.getElementById('sc-' + sid + '-' + term + '-' + sSafeKey);
            if (sc) { const sTotal=calcSubjTotal(sid,term,subj),sMax=getSubjMax(subj,stage),sPct=sMax>0?sTotal/sMax*100:0; sc.innerHTML=`<span style="font-size:13px;font-weight:900;color:${sTotal>0?getGradeColor(sPct):'var(--muted)'}">${sTotal||'—'}</span><span style="font-size:10px;color:var(--muted);font-weight:400">/${sMax}</span>`; }
            // ✅ حفظ تلقائي مشترك — timer واحد لكل الخانات
            clearTimeout(_gradeAutoSaveTimer);
            _gradeAutoSaveTimer = setTimeout(() => saveDB(), 600);
        }
        async function saveAllGrades() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const stage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            const term = (document.getElementById('exam-term-sel') || { value: '' }).value;
            const termNames = { '1': 'الترم الأول', '2': 'الترم الثاني', '3': 'الترم الثالث' };
            logTeacherActivity('درجات', `حفظ الدرجات — المرحلة: ${stage} | ${termNames[term] || 'الترم ' + term}`);
            const btn = document.querySelector('#page-exams .btn-success');
            const orig = btn ? btn.innerHTML : '';
            if (btn) { btn.innerHTML = '⏳ جاري الحفظ...'; btn.disabled = true; }
            try {
                await saveDB();
                showToast('✅ تم حفظ الدرجات بنجاح');
                if (btn) { btn.innerHTML = '✅ تم الحفظ!'; setTimeout(() => { btn.innerHTML = orig; btn.disabled = false; }, 2000); }
            } catch (e) {
                showToast('❌ خطأ في الحفظ: ' + e.message);
                if (btn) { btn.innerHTML = orig; btn.disabled = false; }
            }
        }

        // =========================================================
        // MOBILE GRADE CARD VIEW
        // =========================================================
        let _mgcStudents = [], _mgcIdx = 0, _mgcStage = '', _mgcTerm = '';

        function openMobileGradeView() {
            _mgcStage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            _mgcTerm = (document.getElementById('exam-term-sel') || { value: '1' }).value;
            _mgcStudents = DB.students.filter(s => s.stage === _mgcStage);
            if (!_mgcStudents.length) { showToast('⚠️ لا يوجد طلاب في هذه المرحلة'); return; }
            _mgcIdx = 0;
            document.getElementById('exams-table-card').style.display = 'none';
            document.querySelector('#page-exams .toolbar').style.display = 'none';
            document.querySelector('#page-exams .ph').style.display = 'none';
            document.getElementById('exams-stats-bar').style.display = 'none';
            document.getElementById('quick-report-strip').style.display = 'none';
            document.getElementById('mobile-grade-view').style.display = 'block';
            // Add back button to mobile view
            const wrap = document.querySelector('.mgc-wrap');
            if (!document.getElementById('mgc-back-btn')) {
                const backBtn = document.createElement('button');
                backBtn.id = 'mgc-back-btn';
                backBtn.className = 'btn btn-outline';
                backBtn.style = 'width:100%;margin-bottom:12px;font-size:13px';
                backBtn.innerHTML = '◄ العودة للجدول';
                backBtn.onclick = closeMobileGradeView;
                wrap.insertBefore(backBtn, wrap.firstChild);
            }
            mgcRender();
        }

        function closeMobileGradeView() {
            document.getElementById('exams-table-card').style.display = '';
            document.querySelector('#page-exams .toolbar').style.display = '';
            document.querySelector('#page-exams .ph').style.display = '';
            document.getElementById('exams-stats-bar').style.display = '';
            document.getElementById('quick-report-strip').style.display = '';
            document.getElementById('mobile-grade-view').style.display = 'none';
            renderExamsTable();
        }

        function mgcGo(dir) {
            // flush current card inputs to DB first
            mgcFlushCurrentCard();
            _mgcIdx = Math.max(0, Math.min(_mgcStudents.length - 1, _mgcIdx + dir));
            mgcRender();
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        function mgcFlushCurrentCard() {
            document.querySelectorAll('#mgc-card-area input[data-sid]').forEach(el => handleGradeInput(el));
        }

        function mgcRender() {
            const st = _mgcStudents[_mgcIdx];
            if (!st) return;
            const subjs = DB.subjects[_mgcStage] || [];
            const term = _mgcTerm;
            const fmap = { behavior: 'سلوك', oral: 'شفوي', attendance: 'حضور', written: 'تحريري' };
            const total = applyMercyGrade(calcTotal(st.id, term, _mgcStage), getTermMax(_mgcStage));
            const max = getTermMax(_mgcStage);
            const pct = max > 0 ? Math.round(total / max * 100) : 0;

            document.getElementById('mgc-counter').innerHTML = `<span style="font-weight:900;color:var(--navy)">${_mgcIdx + 1}</span> / ${_mgcStudents.length}`;
            document.getElementById('mgc-prev').disabled = _mgcIdx === 0;
            document.getElementById('mgc-next').disabled = _mgcIdx === _mgcStudents.length - 1;

            let html = `<div class="mgc-card">
    <div class="mgc-card-head">
      <div class="mgc-card-name">${st.name}</div>
      <div class="mgc-card-total" id="mgc-total-display">${total}/${max} (${pct}%)</div>
    </div>`;

            subjs.forEach(s => {
                const flds = ['behavior', 'oral', 'attendance', 'written'].filter(f => s[f] > 0);
                if (!flds.length) return;
                html += `<div class="mgc-subj-block">
      <div class="mgc-subj-title">📚 ${s.name} <span style="font-size:11px;color:var(--muted);font-weight:400">من ${getSubjMax(s.name, _mgcStage)}</span></div>
      <div class="mgc-fields">`;
                const _autoAttM = !!(DB.settings && DB.settings.autoAttendanceEnabled);
                flds.forEach(f => {
                    const val = getGrade(st.id, term, s.name, f) || '';
                    const cls = val > s[f] ? ' over' : val > 0 ? ' filled' : '';
                    if (_autoAttM && f === 'attendance') {
                        html += `<div class="mgc-field">
        <label>${fmap[f]} 🔒</label>
        <input type="number" class="auto-att${val > 0 ? ' filled' : ''}" readonly tabindex="-1" value="${val}" placeholder="—"
          title="تُحسب تلقائيًا من سجل الغياب"
          style="background:#eef6ee;color:#15803d;font-weight:800;cursor:not-allowed">
        <div class="max-hint">من ${s[f]} (تلقائي)</div>
      </div>`;
                    } else {
                        html += `<div class="mgc-field">
        <label>${fmap[f]}</label>
        <input type="number" class="${cls}" inputmode="numeric" min="0" max="${s[f]}" value="${val}" placeholder="—"
          data-sid="${st.id}" data-term="${term}" data-subj="${s.name}" data-field="${f}" data-max="${s[f]}"
          oninput="handleGradeInput(this);mgcUpdateTotal()"
          onchange="handleGradeInput(this);mgcUpdateTotal()">
        <div class="max-hint">من ${s[f]}</div>
      </div>`;
                    }
                });
                html += `</div></div>`;
            });
            html += `</div>`;
            document.getElementById('mgc-card-area').innerHTML = html;
        }

        function mgcUpdateTotal() {
            const st = _mgcStudents[_mgcIdx];
            if (!st) return;
            const total = applyMercyGrade(calcTotal(st.id, _mgcTerm, _mgcStage), getTermMax(_mgcStage));
            const max = getTermMax(_mgcStage);
            const pct = max > 0 ? Math.round(total / max * 100) : 0;
            const el = document.getElementById('mgc-total-display');
            if (el) el.textContent = `${total}/${max} (${pct}%)`;
        }

        async function mgcSaveAndToast() {
            mgcFlushCurrentCard();
            try {
                await saveDB();
                showToast('✅ تم الحفظ');
            } catch (e) { showToast('❌ خطأ: ' + e.message); }
        }

        // =========================================================
        // PASTE FROM EXCEL
        // =========================================================
        let _pasteRows = []; // parsed rows ready to apply

        function openPasteModal() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const stage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            const term = (document.getElementById('exam-term-sel') || { value: '1' }).value;
            const TERM_NAMES = { '1': 'الترم الأول', '2': 'الترم الثاني', '3': 'الترم الثالث' };
            document.getElementById('paste-stage-badge').textContent = 'المرحلة: ' + stage;
            document.getElementById('paste-term-badge').textContent = 'الترم: ' + (TERM_NAMES[term] || term);
            document.getElementById('paste-area').value = '';
            document.getElementById('paste-preview').style.display = 'none';
            document.getElementById('paste-col-map').style.display = 'none';
            document.getElementById('paste-warnings').style.display = 'none';
            document.getElementById('paste-confirm-btn').style.display = 'none';
            document.getElementById('paste-summary').textContent = '';
            document.getElementById('paste-char-count').textContent = '';
            _pasteRows = [];
            openModal('modal-paste-excel');
            setTimeout(() => document.getElementById('paste-area').focus(), 200);
        }

        function parsePasteData() {
            const raw = document.getElementById('paste-area').value;
            const stage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            const term = (document.getElementById('exam-term-sel') || { value: '1' }).value;
            document.getElementById('paste-char-count').textContent = raw.length ? raw.length + ' حرف' : '';

            if (!raw.trim()) {
                document.getElementById('paste-preview').style.display = 'none';
                document.getElementById('paste-col-map').style.display = 'none';
                document.getElementById('paste-warnings').style.display = 'none';
                document.getElementById('paste-confirm-btn').style.display = 'none';
                document.getElementById('paste-summary').textContent = '';
                _pasteRows = [];
                return;
            }

            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            const subjs = DB.subjects[stage] || [];

            // ── Parse tab-separated data ──
            const rawRows = raw.trim().split('\n').map(r => r.split('\t').map(c => c.trim().replace(/\r/, '')));
            if (!rawRows.length) { return; }

            // ── Normalize Arabic ──
            function normAr(s) { return String(s || '').trim().replace(/[أإآا]/g, 'ا').replace(/[ىي]/g, 'ي').replace(/ة/g, 'ه').replace(/\s+/g, ' '); }

            // ── Field keyword map ──
            const FIELD_KW = { behavior: ['سلوك', 'درجه سلوك', 'بهيفيور'], oral: ['شفوي', 'شفهي', 'oral'], attendance: ['حضور', 'مداومه'], written: ['تحريري', 'كتابي', 'written', 'امتحان'] };
            function detectField(h) { const n = normAr(h); for (const [f, kws] of Object.entries(FIELD_KW)) { if (kws.some(k => n.includes(normAr(k)))) return f; } return null; }

            // ── Match student ──
            const studNorm = students.map(s => ({ s, n: normAr(s.name), w: normAr(s.name).split(' ') }));
            function matchStudent(raw) {
                const rn = normAr(raw); if (!rn) return null;
                let m = studNorm.find(x => x.n === rn); if (m) return m.s;
                m = studNorm.find(x => x.n.includes(rn) || rn.includes(x.n)); if (m) return m.s;
                const rw = rn.split(' ');
                m = studNorm.find(x => { const ov = rw.filter(w => w.length > 1 && x.w.includes(w)).length; return ov >= Math.min(2, rw.length, x.w.length); });
                return m ? m.s : null;
            }

            // ── Match subject ──
            const subjNorm = subjs.map(s => ({ s, n: normAr(s.name) }));
            function matchSubj(raw) {
                const rn = normAr(raw.replace(/\s*[\(\[]\d+[\)\]]/g, '').replace(/\s*(من|\/)\s*\d+/g, ''));
                if (!rn) return null;
                let m = subjNorm.find(x => x.n === rn); if (m) return m.s;
                m = subjNorm.find(x => x.n.includes(rn) || rn.includes(x.n)); if (m) return m.s;
                const rw = rn.split(' ').filter(w => w.length > 1);
                m = subjNorm.find(x => rw.some(w => x.n.includes(w))); return m ? m.s : null;
            }

            // ── Detect if first row is a header ──
            const firstRow = rawRows[0];
            const nameColIdx = firstRow.findIndex(h => normAr(h).includes('اسم') || normAr(h).includes('name'));
            // Score: how many cells in first row look like headers vs numbers
            const firstRowNumCount = firstRow.filter(c => c !== '' && !isNaN(parseFloat(c))).length;
            const firstRowTextCount = firstRow.filter(c => c !== '' && isNaN(parseFloat(c))).length;
            const hasHeader = firstRowTextCount >= 2 && firstRowNumCount < 3;

            let headerRow = hasHeader ? firstRow : null;
            const dataRows = hasHeader ? rawRows.slice(1) : rawRows;

            // ── Build column map ──
            // Each col: {idx, type:'name'|'grade'|'skip', subj, field, label, matched}
            const colMap = [];
            const totalCols = Math.max(...rawRows.map(r => r.length));

            if (headerRow) {
                const nameC = nameColIdx >= 0 ? nameColIdx : headerRow.findIndex(h => { const st = matchStudent(h); return !!st; }) || 0;
                headerRow.forEach((h, i) => {
                    if (i === nameC) { colMap.push({ idx: i, type: 'name', label: h || 'الاسم' }); return; }
                    if (!h) { colMap.push({ idx: i, type: 'skip', label: '—' }); return; }
                    // Try "SubjName - field"
                    const dashM = h.match(/^(.+?)\s*[-–]\s*(سلوك|شفوي|حضور|تحريري|oral|written)/i);
                    if (dashM) {
                        const sj = matchSubj(dashM[1]);
                        const ft = { 'سلوك': 'behavior', 'شفوي': 'oral', 'حضور': 'attendance', 'تحريري': 'written', 'oral': 'oral', 'written': 'written' }[dashM[2].toLowerCase()] || 'oral';
                        colMap.push({ idx: i, type: 'grade', subj: sj ? sj.name : dashM[1], field: ft, label: h, matched: !!sj }); return;
                    }
                    // Try field-only
                    const fld = detectField(h);
                    if (fld && colMap.length) {
                        const prev = [...colMap].reverse().find(c => c.type === 'grade' && c.subj);
                        if (prev) { colMap.push({ idx: i, type: 'grade', subj: prev.subj, field: fld, label: h, matched: prev.matched }); return; }
                    }
                    // Try subject name
                    const sj = matchSubj(h);
                    if (sj) { colMap.push({ idx: i, type: 'grade', subj: sj.name, field: 'oral', label: h, matched: true }); return; }
                    colMap.push({ idx: i, type: 'skip', label: h });
                });
            } else {
                // No header: col 0 = name, rest = subjects in order (behavior then oral etc. per subject)
                let subjIdx = 0, fieldIdx = 0;
                const fieldOrder = ['behavior', 'oral', 'attendance', 'written'];
                for (let i = 0; i < totalCols; i++) {
                    if (i === 0) { colMap.push({ idx: i, type: 'name', label: 'الاسم' }); continue; }
                    if (subjIdx >= subjs.length) { colMap.push({ idx: i, type: 'skip', label: 'عمود إضافي' }); continue; }
                    const sj = subjs[subjIdx];
                    // Find active fields in order
                    const activeFields = fieldOrder.filter(f => sj[f] > 0);
                    if (!activeFields.length) { subjIdx++; fieldIdx = 0; i--; continue; }
                    if (fieldIdx >= activeFields.length) { subjIdx++; fieldIdx = 0; i--; continue; }
                    const fld = activeFields[fieldIdx];
                    colMap.push({ idx: i, type: 'grade', subj: sj.name, field: fld, label: `${sj.name} - ${fld}`, matched: true });
                    fieldIdx++;
                    if (fieldIdx >= activeFields.length) { subjIdx++; fieldIdx = 0; }
                }
            }

            // ── Parse data rows ──
            const nameCol = colMap.find(c => c.type === 'name');
            const gradeCol = colMap.filter(c => c.type === 'grade' && c.subj && c.matched);
            _pasteRows = [];
            const unmatched = [];

            dataRows.forEach(row => {
                if (!row.some(c => c !== '')) return; // skip empty
                const nm = row[nameCol ? nameCol.idx : 0] || '';
                if (!nm) return;
                const st = matchStudent(nm);
                if (!st) { if (!unmatched.includes(nm)) unmatched.push(nm); return; }
                const grades = {};
                gradeCol.forEach(col => {
                    const raw = row[col.idx];
                    if (raw === undefined || raw === '') return;
                    const num = parseFloat(raw);
                    if (isNaN(num)) return;
                    if (!grades[col.subj]) grades[col.subj] = { behavior: 0, oral: 0, attendance: 0, written: 0 };
                    grades[col.subj][col.field] = num;
                });
                if (Object.keys(grades).length > 0) _pasteRows.push({ st, grades });
            });

            // ── Render col map badges ──
            const colMapEl = document.getElementById('paste-col-map');
            const colMapBody = document.getElementById('paste-col-map-body');
            colMapBody.innerHTML = colMap.map(c => {
                if (c.type === 'name') return `<span class="paste-col-badge paste-col-name">👤 ${c.label}</span>`;
                if (c.type === 'skip') return `<span class="paste-col-badge paste-col-skip">⏭ ${c.label || 'مجهول'}</span>`;
                const fmap = { behavior: 'سلوك', oral: 'شفوي', attendance: 'حضور', written: 'تحريري' };
                if (c.matched) return `<span class="paste-col-badge paste-col-matched">✅ ${c.subj} · ${fmap[c.field] || c.field}</span>`;
                return `<span class="paste-col-badge paste-col-unmatched">⚠️ ${c.label}</span>`;
            }).join('');
            colMapEl.style.display = 'block';

            // ── Render preview ──
            const previewEl = document.getElementById('paste-preview');
            const previewTable = document.getElementById('paste-preview-table');
            const previewLabel = document.getElementById('paste-preview-label');

            if (_pasteRows.length) {
                const previewSubjs = [...new Set(gradeCol.map(c => c.subj))].slice(0, 6);
                const fmap = { behavior: 'سلوك', oral: 'شفوي', attendance: 'حضور', written: 'تحريري' };
                let html = `<table><thead><tr>
      <th style="text-align:right">الاسم</th>
      ${previewSubjs.map(s => {
                    const flds = gradeCol.filter(c => c.subj === s);
                    return `<th colspan="${flds.length}">${s}</th>`;
                }).join('')}
    </tr><tr>
      <th></th>
      ${previewSubjs.flatMap(s => gradeCol.filter(c => c.subj === s).map(c => `<th style="font-size:10px">${fmap[c.field] || c.field}</th>`)).join('')}
    </tr></thead><tbody>`;
                _pasteRows.slice(0, 10).forEach(r => {
                    html += `<tr><td style="text-align:right;font-weight:700;font-size:12px">${r.st.name}</td>`;
                    previewSubjs.forEach(s => {
                        gradeCol.filter(c => c.subj === s).forEach(c => {
                            const v = (r.grades[s] || {})[c.field];
                            const sj = subjs.find(x => x.name === s);
                            const mx = sj ? sj[c.field] : 999;
                            const over = v !== undefined && v > mx;
                            html += v !== undefined
                                ? `<td><span style="font-weight:700;color:${over ? '#c00' : 'var(--green)'}">${v}</span>${over ? `<span style="font-size:9px;color:#c00"> >/${mx}</span>` : ''}</td>`
                                : `<td style="color:#ddd">—</td>`;
                        });
                    });
                    html += `</tr>`;
                });
                if (_pasteRows.length > 10) html += `<tr><td colspan="20" style="text-align:center;color:var(--muted);font-size:11px">... و ${_pasteRows.length - 10} طالب آخر</td></tr>`;
                html += `</tbody></table>`;
                previewTable.innerHTML = html;
                previewLabel.textContent = `👁 معاينة — ${_pasteRows.length} طالب جاهزين للإدخال`;
                previewEl.style.display = 'block';
            } else {
                previewEl.style.display = 'none';
            }

            // ── Warnings ──
            const warnEl = document.getElementById('paste-warnings');
            const warns = [];
            if (unmatched.length) warns.push(`⚠️ ${unmatched.length} صف لم يُطابق: <b>${unmatched.slice(0, 3).join('، ')}</b>${unmatched.length > 3 ? '...' : ''}`);
            const unmatchedCols = colMap.filter(c => c.type === 'grade' && !c.matched);
            if (unmatchedCols.length) warns.push(`⚠️ ${unmatchedCols.length} أعمدة لم تُطابق بمادة في النظام`);
            if (warns.length) {
                warnEl.style.display = 'block';
                warnEl.innerHTML = warns.map(w => `<div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:8px;padding:8px 12px;font-size:12px;color:#92400e;margin-bottom:6px">${w}</div>`).join('');
            } else {
                warnEl.style.display = 'none';
            }

            // ── Summary & confirm button ──
            const matched = _pasteRows.length;
            const totalGrades = _pasteRows.reduce((acc, r) => acc + Object.values(r.grades).reduce((a, g) => a + Object.values(g).filter(v => v > 0).length, 0), 0);
            document.getElementById('paste-summary').textContent = matched ? `سيتم إدخال ${totalGrades} درجة لـ ${matched} طالب` : 'لم يتم التعرف على بيانات صالحة';
            document.getElementById('paste-confirm-btn').style.display = matched ? 'inline-flex' : 'none';
        }

        function applyPastedGrades() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            if (!_pasteRows.length) { showToast('⚠️ لا توجد بيانات'); return; }
            const term = (document.getElementById('exam-term-sel') || { value: '1' }).value;
            const stage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            const subjs = DB.subjects[stage] || [];
            let applied = 0, capped = 0;

            _pasteRows.forEach(({ st, grades }) => {
                Object.entries(grades).forEach(([subjName, g]) => {
                    const sj = subjs.find(x => x.name === subjName);
                    ['behavior', 'oral', 'attendance', 'written'].forEach(f => {
                        if (g[f] === undefined) return;
                        let val = +g[f];
                        const mx = sj ? +sj[f] : 999;
                        if (val > mx) { val = mx; capped++; }
                        if (val < 0) val = 0;
                        setGrade(st.id, term, subjName, f, val);
                        applied++;
                    });
                });
            });

            saveDB();
            closeModal('modal-paste-excel');
            renderExamsTable();
            let msg = `✅ تم إدخال ${applied} درجة لـ ${_pasteRows.length} طالب`;
            if (capped) msg += ` — ⚠️ ${capped} درجة جُعلت بالحد الأقصى`;
            showToast(msg);
            _pasteRows = [];
        }


        function confirmDeleteTermGrades() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const stage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            const term = (document.getElementById('exam-term-sel') || { value: '1' }).value;
            if (!stage) { showToast('⚠️ اختر المرحلة أولاً'); return; }
            const TERM_NAMES = { 1: 'الترم الأول', 2: 'الترم الثاني', 3: 'الترم الثالث' };
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            // Count matching keys: sid_t{term}_{subj}
            const prefix_t = '_t' + term + '_';
            const studentIds = new Set(students.map(s => s.id));
            let gradesCount = 0;
            Object.keys(DB.grades || {}).forEach(k => {
                const parts = k.split(prefix_t);
                if (parts.length === 2 && studentIds.has(parts[0])) {
                    const g = DB.grades[k] || {};
                    ['behavior', 'oral', 'attendance', 'written'].forEach(f => { if (+g[f] > 0) gradesCount++; });
                }
            });
            document.getElementById('delete-term-confirm-text').innerHTML =
                `سيتم حذف درجات <b>${TERM_NAMES[term] || 'الترم ' + term}</b><br>
    المرحلة: <b>${stage}</b><br>
    عدد الطلاب: <b>${students.length}</b><br>
    عدد الدرجات المسجلة: <b style="color:#c0392b">${gradesCount} درجة</b>`;
            openModal('modal-delete-term-grades');
        }

        function executeDeleteTermGrades() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const stage = (document.getElementById('exam-stage-sel') || { value: '' }).value;
            const term = (document.getElementById('exam-term-sel') || { value: '1' }).value;
            const TERM_NAMES = { 1: 'الترم الأول', 2: 'الترم الثاني', 3: 'الترم الثالث' };
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            const studentIds = new Set(students.map(s => s.id));
            const prefix_t = '_t' + term + '_';
            let deleted = 0;
            const keysToDelete = Object.keys(DB.grades || {}).filter(k => {
                const parts = k.split(prefix_t);
                return parts.length === 2 && studentIds.has(parts[0]);
            });
            keysToDelete.forEach(k => {
                const g = DB.grades[k] || {};
                ['behavior', 'oral', 'attendance', 'written'].forEach(f => { if (+g[f] > 0) deleted++; });
                delete DB.grades[k];
            });
            saveDB();
            closeModal('modal-delete-term-grades');
            renderExamsTable();
            showToast(`🗑️ تم حذف ${deleted} درجة من ${TERM_NAMES[term] || 'الترم ' + term} — ${stage}`);
        }

        // =========================================================
        // CERTIFICATES
        // =========================================================
        function renderCertificates() {
            const stage = (document.getElementById('cert-stage-sel') || { value: STAGES[0] }).value;
            const term = (document.getElementById('cert-term-sel') || { value: '1' }).value;
            const cntEl = document.getElementById('cert-student-count'); if (cntEl) cntEl.textContent = DB.students.filter(s => s.stage === stage && !isGraduate(s)).length + ' طالب';
            // v34: حدّث قائمة "طالب محدد"
            try { if (typeof populateCertStudentsSelector === 'function') populateCertStudentsSelector(); } catch (_) {}
            const q = ((document.getElementById('cert-search') || {}).value || '').toLowerCase();
            const students = _sortStudentsForPrint(DB.students.filter(s => s.stage === stage && !isGraduate(s) && (!q || s.name.toLowerCase().includes(q))), stage, term);
            const subjs = DB.subjects[stage] || []; const container = document.getElementById('certs-container');
            if (!students.length) { container.innerHTML = '<div class="empty-state"><div class="icon">🏆</div><p>لا يوجد طلاب</p></div>'; return; }
            const infoBanner = `<div class="certs-info-banner">
  <div class="cib-item"><span class="cib-label">📚 المرحلة</span><span class="cib-value">${stage}</span></div>
  <div class="cib-divider"></div>
  <div class="cib-item"><span class="cib-label">📅 الترم</span><span class="cib-value">${TERM_NAMES[term]}</span></div>
  <div class="cib-divider"></div>
  <div class="cib-item"><span class="cib-label">🗓️ العام الدراسي</span><span class="cib-value">${DB.schoolYear || '—'}</span></div>
  <div class="cib-divider"></div>
  <div class="cib-item"><span class="cib-label">👥 عدد الطلاب</span><span class="cib-value">${students.length} طالب</span></div>
</div>`;
            container.innerHTML = infoBanner + students.map(st => {
                const rawTotal = calcTotal(st.id, term, stage), max = getTermMax(stage), total = applyMercyGrade(rawTotal, max), pct = max > 0 ? total / max * 100 : 0;
                const photoHtml = st.photo ? `<img src="${st.photo}" class="cert-photo">` : '';
                const fmapR = { behavior: 'سلوك', oral: 'شفوي', attendance: 'حضور', written: 'تحريري' };
                // v34: زر طباعة شهادة هذا الطالب فقط
                const printBtn = `<button class="btn btn-primary allow-ro" style="font-size:11px;padding:5px 10px;margin-right:8px" title="طباعة شهادة هذا الطالب" onclick="printSingleCert('${st.id}','${stage}','${term}')">🖨️ طباعة</button>`;
                return `<div class="cert-card"><div class="cert-header"><div style="display:flex;align-items:center;gap:12px">${photoHtml}<div><div class="cert-name">${st.name}</div><div class="cert-stage">${st.stage} — ${TERM_NAMES[term]} — ${DB.schoolYear}</div></div></div><div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap"><span class="badge ${getGradeClass(pct)}" style="font-size:13px;padding:6px 14px">${getGradeText(pct)} — ${pct.toFixed(1)}%</span>${printBtn}</div></div>
    <div class="cert-subjects">${subjs.map(s => { const t = calcSubjTotal(st.id, term, s.name), m = getSubjMax(s.name, stage), sp = m > 0 ? t / m * 100 : 0; const flds = ['behavior','oral','attendance','written'].filter(f => s[f] > 0); const bkdn = flds.length > 1 ? `<div style="margin:4px 0;border-top:1px solid var(--border);padding-top:3px;width:100%">${flds.map(f => `<div style="display:flex;justify-content:space-between;font-size:9px;padding:1px 2px"><span style="color:var(--muted);font-weight:700">${fmapR[f]}</span><span style="font-weight:900">${getGrade(st.id, term, s.name, f)||0}<span style="color:var(--muted);font-weight:400">/${s[f]}</span></span></div>`).join('')}</div>` : ''; return `<div class="subj-box"><div class="sname">${s.name}</div>${bkdn}<div class="sgrade" style="color:${getGradeColor(sp)};font-size:${flds.length>1?'17':'20'}px">${t}</div><div class="smax">من ${m}</div></div>`; }).join('')}</div>
    <div style="display:flex;align-items:center;justify-content:space-between;padding-top:12px;border-top:1px solid var(--border)"><div style="font-size:22px;font-weight:900;color:var(--navy)">${total} / ${max}</div><div style="font-size:13px;color:var(--muted)">${pct.toFixed(1)}% — ${getGradeText(pct)}</div></div></div>`;
            }).join('');
        }

        // =========================================================
        // ANNUAL
        // =========================================================
        function renderAnnual() {
            const stage = (document.getElementById('annual-stage-sel') || { value: STAGES[0] }).value;
            const q = ((document.getElementById('annual-search') || {}).value || '').toLowerCase();
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s) && (!q || s.name.toLowerCase().includes(q)));
            const subjs = DB.subjects[stage] || []; const container = document.getElementById('annual-container');
            if (!students.length) { container.innerHTML = '<div class="empty-state"><div class="icon">🎓</div><p>لا يوجد طلاب</p></div>'; return; }
            const _gradeSorted = students.map(st => { const terms = [1, 2, 3].map(t => ({ term: t, total: calcTotal(st.id, String(t), stage), max: getTermMax(stage) })); const rawGt = terms.reduce((s, t) => s + t.total, 0), gm = terms.reduce((s, t) => s + t.max, 0), gt = applyMercyGrade(rawGt, gm), pct = gm > 0 ? gt / gm * 100 : 0; return { ...st, terms, gt, gm, pct }; }).sort((a, b) => b.pct - a.pct);
            const sorted = ((DB.settings && DB.settings.sortMode) === 'alpha') ? _sortStudentsForPrint(_gradeSorted, stage, '1') : _gradeSorted;
            const _acStyle = (DB.settings && DB.settings.annualCertStyle) || 'classic';
            const _acToggle = `<div class="no-print" style="display:flex;justify-content:center;margin:6px 0 16px"><div class="tc-style-toggle">
                <button class="${_acStyle === 'luxe' ? 'active' : ''}" onclick="setAnnualCertStyle('luxe')">🌌 فاخر داكن</button>
                <button class="${_acStyle === 'classic' ? 'active' : ''}" onclick="setAnnualCertStyle('classic')">📜 كلاسيكي فاتح</button>
            </div></div>`;
            container.innerHTML = _annualCertStyles() + _acToggle + sorted.map((st, rank) => _annualCertCard(st, rank, stage)).join('');
        }

        // =========================================================
        // TOTAL
        // =========================================================
        function renderTotal() {
            const stage = (document.getElementById('total-stage-sel') || { value: STAGES[0] }).value;
            const q = ((document.getElementById('total-search') || {}).value || '').toLowerCase();
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s) && (!q || s.name.toLowerCase().includes(q)));
            const max = getTermMax(stage);
            document.getElementById('total-thead').innerHTML = `<tr><th>الاسم</th><th>ترم 1 (/${max})</th><th>ترم 2 (/${max})</th><th>ترم 3 (/${max})</th><th>المجموع (/${max * 3})</th><th>النسبة</th><th>التقدير</th></tr>`;
            const _ranked = students.map(st => { const terms = [1, 2, 3].map(t => calcTotal(st.id, String(t), stage)); const rawGrand = terms.reduce((s, x) => s + x, 0), gMax = max * 3, grand = applyMercyGrade(rawGrand, gMax), pct = gMax > 0 ? grand / gMax * 100 : 0; return { ...st, terms, grand, pct }; }).sort((a, b) => b.pct - a.pct);
            const sorted = ((DB.settings && DB.settings.sortMode) === 'alpha') ? _sortStudentsForPrint(_ranked, stage, '1') : _ranked;
            document.getElementById('total-tbody').innerHTML = sorted.map((st, i) => `<tr><td class="td-name">${i + 1}. ${st.name}</td>${st.terms.map(t => `<td style="font-weight:700">${t}</td>`).join('')}<td><strong style="font-size:14px">${st.grand}</strong></td><td><span style="font-weight:900;color:${getGradeColor(st.pct)}">${st.pct.toFixed(1)}%</span></td><td><span class="badge ${getGradeClass(st.pct)}">${getGradeText(st.pct)}</span></td></tr>`).join('') || '<tr><td colspan="7" style="padding:24px;text-align:center;color:var(--muted)">لا يوجد طلاب</td></tr>';
        }

        // =========================================================
        // ABSENCE — نظام الحضور والغياب بالجلسات
        // =========================================================
        function getSchoolYearForMonth(month) {
            const parts = (DB.schoolYear || '2024/2025').split('/');
            const y1 = parseInt(parts[0]) || 2024;
            const y2 = parseInt(parts[1]) || (y1 + 1);
            return month >= 9 ? y1 : y2;
        }
        function getSundaysInMonth(year, month) {
            const sundays = [];
            const d = new Date(year, month - 1, 1);
            while (d.getDay() !== 0) d.setDate(d.getDate() + 1);
            while (d.getMonth() === month - 1) { sundays.push(new Date(d)); d.setDate(d.getDate() + 7); }
            return sundays;
        }
        function formatDate(d) { return `${d.getDate()}/${d.getMonth() + 1}`; }
        function getSessionCount(month) {
            // 1) تحقق من الـ input في الصفحة (override يدوي)
            const overrideEl = document.getElementById('abs-sessions-override');
            if (overrideEl && overrideEl.value && +overrideEl.value > 0) return +overrideEl.value;
            // 2) الإعداد المحفوظ
            if (DB && DB.settings && DB.settings.weeklySessionCount) return DB.settings.weeklySessionCount;
            // 3) احسب الأحاد في الشهر
            const year = getSchoolYearForMonth(month);
            return getSundaysInMonth(year, month).length;
        }
        function absSessionsChanged() {
            renderAbsence();
            const month = +((document.getElementById('abs-month-sel') || { value: 9 }).value);
            const n = getSessionCount(month);
            const badge = document.getElementById('abs-sessions-badge');
            if (badge) badge.textContent = n + ' حصة';
        }

        // ── saveAbsence: حفظ يدوي (الزرار "💾 حفظ") ──
        function saveAbsence() {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط — لا يمكن الحفظ'); return; }
            const stage = (document.getElementById('abs-stage-sel') || {}).value || '';
            const monthVal = (document.getElementById('abs-month-sel') || {}).value || '';
            const monthNames = ['', 'يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو', 'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر'];
            const subj = (document.getElementById('abs-subj-sel') || {}).value || '';
            logTeacherActivity('غياب', `حفظ سجل الغياب — المرحلة: ${stage} | الشهر: ${monthNames[+monthVal] || monthVal}${subj ? ' | المادة: ' + subj : ''}`);
            try { if (stage && monthVal) _recalcAttendanceForMonth(stage, +monthVal); } catch (e) { }
            saveDB();
            showToast('✅ تم حفظ سجل الغياب');
        }

        function absStageChanged() {
            const stage = (document.getElementById('abs-stage-sel') || {}).value;
            const sel = document.getElementById('abs-subj-sel');
            if (!sel) return;
            const subjs = (DB.subjects[stage] || []).map(s => s.name);
            const cur = sel.value;
            sel.innerHTML = subjs.map(s => `<option value="${s}">${s}</option>`).join('');
            if (cur && subjs.includes(cur)) sel.value = cur;
            renderAbsence();
        }

        function renderAbsence() {
            const stage = (document.getElementById('abs-stage-sel') || { value: STAGES[0] }).value;
            const month = +((document.getElementById('abs-month-sel') || { value: 9 }).value);
            const subjSel = document.getElementById('abs-subj-sel');
            const subj = subjSel ? subjSel.value : '';
            const allowedStgs3 = IS_TEACHER_MODE ? getTeacherAllowedStages() : null;
            const students = _sortStudentsForPrint(DB.students.filter(s => s.stage === stage && !isGraduate(s) && (!allowedStgs3 || allowedStgs3.includes(s.stage))), stage, '1');
            const sessions = getSessionCount(month);
            // تحديث badge عدد الحصص
            const badge = document.getElementById('abs-sessions-badge');
            if (badge) badge.textContent = sessions + ' حصة';
            const wrap = document.getElementById('abs-table-wrap');
            const cntEl = document.getElementById('abs-student-count');
            if (cntEl) cntEl.textContent = students.length + ' طالب';
            if (!students.length) { wrap.innerHTML = '<div style="padding:24px;text-align:center;color:var(--muted)">لا يوجد طلاب في هذه المرحلة</div>'; return; }
            if (!subj) { wrap.innerHTML = '<div style="padding:24px;text-align:center;color:var(--muted)">اختر المادة أولاً</div>'; return; }
            const monthNames = ['', 'يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو', 'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر'];

            let totalAbsent = 0;
            let html = `<table><thead><tr>
    <th style="text-align:right;min-width:160px;position:sticky;right:0;z-index:3;background:linear-gradient(135deg,var(--navy),var(--navy-light))">الاسم (${students.length} طالب)</th>
    ${Array.from({ length: sessions }, (_, i) => `<th style="min-width:72px">حصة ${i + 1}<br><button class="abs-col-btn" onclick="absMarkAll(${i + 1},'غ','${subj}',${month})" title="كل الفصل غاب">كل غ</button><button class="abs-col-btn" style="background:rgba(39,174,96,.25);margin-top:2px" onclick="absMarkAll(${i + 1},'ح','${subj}',${month})" title="كل الفصل حضر">كل ح</button></th>`).join('')}
    <th style="min-width:80px">غياب / ${sessions}</th>
  </tr></thead><tbody>`;

            students.forEach(st => {
                const k = `${st.id}_${month}_${subj}`;
                const absData = DB.absence[k] || {};
                let absDays = 0;
                html += `<tr><td class="td-name sticky-col" onclick="openSP('${st.id}')" style="cursor:pointer" title="عرض ملف الطالب">${st.name}${(st.status || '').indexOf('راسب') !== -1 ? ' <span style="background:#fecaca;color:#991b1b;border-radius:8px;padding:0 5px;font-size:9px;font-weight:900">🔄 معيد</span>' : ''}</td>`;
                for (let w = 1; w <= sessions; w++) {
                    const absent = absData[w] ? 1 : 0;
                    absDays += absent;
                    html += `<td style="text-align:center;padding:4px 3px">
        <div id="abs-cell-${st.id}-${month}-${w}"
          data-sid="${st.id}" data-month="${month}" data-subj="${subj}" data-week="${w}" data-absent="${absent}"
          onclick="${IS_EDIT_MODE ? `toggleAbsCell(this)` : ''}"
          style="cursor:${IS_EDIT_MODE ? 'pointer' : 'default'};display:inline-flex;align-items:center;justify-content:center;min-width:52px;min-height:52px;border-radius:12px;border:2px solid ${absent ? '#c0392b' : '#c8e6c9'};background:${absent ? '#fdecea' : '#f0faf0'};transition:background .15s,border .15s;-webkit-tap-highlight-color:transparent;touch-action:manipulation">
          <span style="font-size:26px;line-height:1;user-select:none;pointer-events:none">${absent ? '❌' : '✅'}</span>
        </div>
      </td>`;
                }
                if (absDays > 0) totalAbsent++;
                const pct = sessions > 0 ? Math.round(absDays / sessions * 100) : 0;
                const badge = pct >= 60 ? 'b-danger' : pct >= 33 ? 'b-warn' : 'b-success';
                html += `<td id="abs-total-${st.id}-${month}" style="text-align:center"><span class="badge ${badge}" style="font-size:13px;padding:5px 12px">${absDays} / ${sessions}</span></td></tr>`;
            });
            html += `</tbody></table>`;
            wrap.innerHTML = html;

            const sumEl = document.getElementById('abs-summary');
            if (sumEl) sumEl.innerHTML = `<span style="color:var(--muted);font-size:12px">📚 <strong>${subj}</strong> &nbsp;|&nbsp; مواظب: <strong style="color:var(--green)">${students.length - totalAbsent}</strong> &nbsp;|&nbsp; غاب: <strong style="color:var(--danger)">${totalAbsent}</strong> &nbsp;|&nbsp; ${monthNames[month]} — ${sessions} حصص</span>`;

            const maxPct = DB.settings && DB.settings.absMaxPct || 60;
            const critCount = students.filter(st => {
                const d = DB.absence[`${st.id}_${month}_${subj}`] || {};
                let a = 0; for (let w = 1; w <= sessions; w++)if (d[w]) a++;
                return sessions > 0 && a / sessions * 100 >= maxPct;
            }).length;
            const stageBar = document.getElementById('abs-stage-stats');
            if (stageBar) stageBar.innerHTML = `
    <div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:var(--navy)">📋 ${students.length} طالب</div>
    <div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);border:1px solid #86efac;border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:#166534">✅ مواظب: ${students.length - totalAbsent}</div>
    <div style="background:linear-gradient(135deg,#fff8e1,#fef3c7);border:1px solid #fbbf24;border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:#92400e">⚠️ غاب: ${totalAbsent}</div>
    <div style="background:var(--card);border:1px solid var(--border);border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:var(--muted)">📅 ${monthNames[month]} — ${sessions} حصص</div>
    ${critCount ? `<div style="background:linear-gradient(135deg,#fef2f2,#fee2e2);border:1px solid #fca5a5;border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:#991b1b">🚨 غياب عالي: ${critCount} طالب</div>` : '<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);border:1px solid #86efac;border-radius:10px;padding:8px 14px;font-size:12px;font-weight:700;color:#166534">🎯 لا أحد تجاوز الحد</div>'}`;
        }

        function absMarkAll(week, type, subj, month) {
            if (!IS_EDIT_MODE) { showToast('⚠️ وضع عرض فقط'); return; }
            const stage = (document.getElementById('abs-stage-sel') || { value: '' }).value;
            const students = DB.students.filter(s => s.stage === stage && !isGraduate(s));
            const isAbsent = (type === 'غ');
            students.forEach(st => {
                const k = `${st.id}_${month}_${subj}`;
                if (!DB.absence[k]) DB.absence[k] = {};
                if (isAbsent) DB.absence[k][week] = 1;
                else delete DB.absence[k][week];
                // تحديث الخلية مباشرة
                const cell = document.getElementById(`abs-cell-${st.id}-${month}-${week}`);
                if (cell) {
                    cell.dataset.absent = isAbsent ? '1' : '0';
                    cell.style.border = `2px solid ${isAbsent ? '#c0392b' : '#c8e6c9'}`;
                    cell.style.background = isAbsent ? '#fdecea' : '#f0faf0';
                    const sp = cell.querySelector('span'); if (sp) sp.textContent = isAbsent ? '❌' : '✅';
                    // تحديث الإجمالي
                    const sessions = getSessionCount(month);
                    let absDays = 0;
                    for (let w = 1; w <= sessions; w++) if (DB.absence[k][w]) absDays++;
                    const pct = sessions > 0 ? Math.round(absDays / sessions * 100) : 0;
                    const badge = pct >= 60 ? 'b-danger' : pct >= 33 ? 'b-warn' : 'b-success';
                    const totalEl = document.getElementById(`abs-total-${st.id}-${month}`);
                    if (totalEl) totalEl.innerHTML = `<span class="badge ${badge}" style="font-size:13px;padding:5px 12px">${absDays} / ${sessions}</span>`;
                }
            });
            try { _recalcAttendanceForMonth(stage, month); } catch (e) { }
            clearTimeout(absMarkAll._t);
            absMarkAll._t = setTimeout(() => { saveDB(); showToast(isAbsent ? `✅ تم تسجيل غياب الجميع في الحصة ${week}` : `✅ تم تسجيل حضور الجميع في الحصة ${week}`); }, 300);
        }

