            const USABLE = 285, NAME_W = 46, NUM_W = 8;
            const fieldWmm = mx => { const n = Math.max(2, String(mx).length); return n * 12 + (n - 1) * 1.4 + 4.5; };
            const groupWmm = g => g.fields.reduce((a, f) => a + fieldWmm(f.max), 0);

            // تقسيم المواد على صفحات أفقياً حسب العرض المتاح
            const colPages = []; let cur = [], curW = NAME_W + NUM_W;
            groups.forEach(g => {
                const w = groupWmm(g);
                if (cur.length && curW + w > USABLE) { colPages.push(cur); cur = []; curW = NAME_W + NUM_W; }
                cur.push(g); curW += w;
            });
            if (cur.length) colPages.push(cur);

