                results: document.getElementById('perm-results')?.checked || false,
                graduation: document.getElementById('perm-graduation')?.checked || false,
                books: document.getElementById('perm-books')?.checked || false,
                examFiles: document.getElementById('perm-exam-files')?.checked || false,
                media: document.getElementById('perm-media')?.checked || false,
                scheduleDetail: document.getElementById('perm-schedule-detail')?.checked || false,
                deacons: document.getElementById('perm-deacons')?.checked || false,
                printTeacherName: document.getElementById('perm-print-teacher-name')?.checked || false,
                printShowDate: document.getElementById('perm-print-show-date')?.checked ?? true,
                printShowStudentCount: document.getElementById('perm-print-student-count')?.checked ?? true,
                printShowSignature: document.getElementById('perm-print-signature')?.checked ?? true,
